/**
 * List folders and documents in an R7-Disk directory.
 * @param {Record<string, unknown>} state
 * @param {{
 *   directory_id?: unknown,
 *   disk_section?: unknown,
 *   web_url?: unknown,
 *   auth_token?: unknown,
 *   base_url?: unknown,
 *   login?: unknown,
 *   password?: unknown,
 *   force_repeat?: unknown
 * }} params
 */
async function handler(state, params) {
	const userEnv = readUserEnv(state);
	const skillStorage = resolveSkillStorage(state);

	const baseUrl = resolveBaseUrl(state, params, skillStorage);
	const login = pickString(params?.login, userEnv.R7_DISK_LOGIN);
	const password = pickString(params?.password, userEnv.R7_DISK_PASSWORD);
	if (!baseUrl) {
		return { ok: false, error: 'Не задан R7_DISK_BASE_URL.' };
	}

	let authToken = typeof params?.auth_token === 'string' ? params.auth_token.trim() : '';
	let authFromCache = Boolean(authToken);
	if (!authToken && skillStorage) {
		const cached = skillStorage.get('r7_disk_auth_token');
		if (typeof cached === 'string' && cached.trim()) {
			authToken = cached.trim();
			authFromCache = true;
		}
	}

	if (!authToken) {
		const loginResult = await loginInline(baseUrl, login, password, skillStorage);
		if (!loginResult.ok) return loginResult;
		authToken = loginResult.auth_token;
		authFromCache = false;
	}

	const resolved = await resolveListingDirectoryId({
		params,
		baseUrl,
		authToken,
		skillStorage,
		userEnv
	});
	if (!resolved.ok) {
		return { ok: false, error: resolved.error };
	}
	const directoryId = resolved.directory_id;
	const diskSection = resolved.disk_section;

	const listingDedupHit = resolveListingDedupHit(skillStorage, directoryId, diskSection, params);
	if (listingDedupHit) {
		return withSessionAuthHints(listingDedupHit, authFromCache);
	}

	const listBlockedAfterRead = resolveListBlockedAfterRead(skillStorage, directoryId, params);
	if (listBlockedAfterRead) {
		return withSessionAuthHints(listBlockedAfterRead, authFromCache);
	}

	const url = `${baseUrl}/api/v1/DocumentDirectory/Get?id=${encodeURIComponent(String(directoryId))}`;
	let response;
	try {
		response = await fetch(url, {
			method: 'GET',
			headers: {
				'Content-Type': 'application/json',
				Authorization: authToken
			}
		});
	} catch (err) {
		return {
			ok: false,
			error: `Сетевая ошибка Get: ${errorMessage(err)}`
		};
	}

	const rawText = await readUtf8Text(response);
	if (!response.ok) {
		const guessedId = directoryId <= 10;
		const accessDenied = response.status === 403 || response.status === 406;
		return {
			ok: false,
			error: `DocumentDirectory/Get HTTP ${response.status}: ${truncate(rawText, 300)}`,
			...(accessDenied && guessedId
				? {
						do_not_guess_directory_ids: true,
						forbid_directory_id_probe: true,
						agent_message:
							`Нет доступа к папке id=${directoryId}. **Не перебирайте** id 1–4 и другие «наугад». ` +
							'Спросите у пользователя **имя папки** или URL `/docs/N`, либо вызовите `r7_disk_browse` с `folder_name`.',
						hint:
							'После login с `my_documents_directory_id: null` — один вопрос пользователю, не серия list_directory с разными id.'
					}
				: {})
		};
	}

	let payload;
	try {
		payload = rawText ? JSON.parse(rawText) : [];
	} catch {
		return { ok: false, error: `Get: ответ не JSON: ${truncate(rawText, 300)}` };
	}

	const entries = Array.isArray(payload) ? payload : [payload];
	const entry = entries.find((item) => item && typeof item === 'object') ?? entries[0];
	if (!entry || typeof entry !== 'object') {
		return { ok: false, error: 'Пустой ответ DocumentDirectory/Get.' };
	}

	const stored = readRootsFromStorage(skillStorage);
	const folders = normalizeFolderList(entry.Children);
	const rawDocuments = normalizeDocumentList(entry.Documents);
	const dirId = typeof entry.Id === 'number' ? entry.Id : directoryId;
	const dirName = typeof entry.Name === 'string' ? entry.Name : '';
	const effectiveDiskSection = inferEffectiveDiskSection(
		diskSection ?? 'docs',
		dirId,
		dirName,
		stored.sectionRoots
	);
	const strictDocumentFilter = shouldStrictFilterDocuments(
		effectiveDiskSection,
		dirId,
		dirName,
		stored.sectionRoots
	);
	const documents = strictDocumentFilter
		? filterDocumentsForDirectory(rawDocuments, dirId)
		: rawDocuments;
	const documentsFilteredOut = strictDocumentFilter
		? rawDocuments.length - documents.length
		: 0;
	const parent =
		entry.Parent && typeof entry.Parent === 'object' ? entry.Parent : null;
	const parentId =
		parent && typeof parent.Id === 'number' ? parent.Id : null;
	const parentName =
		parent && typeof parent.Name === 'string' ? parent.Name : null;

	const parentChain = await buildParentChain(baseUrl, authToken, dirId);
	let personalRootId = stored.personalRootId;
	if (personalRootId == null) {
		const inferred = inferPersonalRootFromListing(parentId, parentName, parentChain);
		if (inferred != null) {
			personalRootId = inferred.id;
			persistPersonalRootToStorage(skillStorage, inferred.id, inferred.name);
		}
	}
	const isPersonalTree = isUnderPersonalRoot(personalRootId, dirId, parentChain);
	const isVirtualSection = !strictDocumentFilter;
	const isEmpty = folders.length === 0 && documents.length === 0;

	/** @type {string} */
	let listing_scope_note;
	if (documentsFilteredOut > 0 && isEmpty) {
		listing_scope_note =
			`Папка «${dirName}» (id=${dirId}): пусто. ` +
			`API вернул ${documentsFilteredOut} файл(ов) из других папок — отфильтрованы по DirectoryId.`;
	} else if (isEmpty) {
		listing_scope_note = `Папка «${dirName}» (id=${dirId}): пусто — нет подпапок и файлов.`;
	} else if (parentId != null && parentName) {
		listing_scope_note = `Папка «${dirName}» (id=${dirId}), родитель: «${parentName}» (id=${parentId}).`;
	} else if (isVirtualSection) {
		listing_scope_note = `Раздел «${dirName}» (id=${dirId}, disk_section=${effectiveDiskSection}).`;
	} else {
		listing_scope_note = `Папка «${dirName}» (id=${dirId}) — корень запроса (disk_section=${effectiveDiskSection}).`;
	}

	const scopeWarning =
		personalRootId != null && !isPersonalTree && effectiveDiskSection === 'docs'
			? 'Каталог вне личного «Мои документы» — возможно общий или расшаренный.'
			: '';

	const storageState =
		dirId === personalRootId && isEmpty
			? 'personal_empty'
			: dirId === personalRootId
				? 'personal_with_content'
				: stored.storageState;

	const subfoldersOnlyAtRoot =
		dirId === personalRootId &&
		folders.length > 0 &&
		documents.length === 0 &&
		!isVirtualSection;
	const listingAgentMessage = isEmpty
		? isVirtualSection
			? `${listing_scope_note} В этом разделе пока нет расшаренных файлов.`
			: `${listing_scope_note} Можно создать папку или файл — см. create_target.`
		: subfoldersOnlyAtRoot
			? `${listing_scope_note} Файлы лежат в подпапках — вызовите r7_disk_browse (directory_id=${dirId}) и покажите all_documents.`
			: listing_scope_note;

	const listingResult = withFactualCitation(
			{
				ok: true,
				directory_id: dirId,
				directory_name: dirName,
				disk_section: effectiveDiskSection,
				is_virtual_section: isVirtualSection,
				parent,
				parent_directory_id: parentId,
				parent_directory_name: parentName,
				parent_chain: parentChain,
				is_personal_tree: isPersonalTree,
				is_empty: isEmpty,
				storage_state: storageState,
				create_target: stored.createTarget,
				web_url_hint: buildWebUrlHint(effectiveDiskSection, dirId),
				scope_warning: scopeWarning || undefined,
				listing_scope_note,
				...(documentsFilteredOut > 0
					? { documents_filtered_out: documentsFilteredOut }
					: {}),
				...(subfoldersOnlyAtRoot
					? {
							subfolders_only: true,
							needs_browse_for_files: true,
							browse_hint: {
								tool: 'r7_disk_browse',
								directory_id: dirId,
								my_documents_directory_id: dirId
							}
						}
					: {}),
				folders,
				documents,
				counters: entry.Counters && typeof entry.Counters === 'object' ? entry.Counters : null,
				agent_message: listingAgentMessage,
				api_base_url: baseUrl
			},
			['folders', 'documents', 'listing_scope_note', 'directory_name', 'directory_id']
			);

	persistListingDedup(skillStorage, dirId, effectiveDiskSection, listingResult);

	const forbidAfterList = subfoldersOnlyAtRoot
		? ['r7_disk_list_directory', 'list_directory', 'r7_disk_login']
		: ['r7_disk_list_directory', 'list_directory', 'r7_disk_browse', 'browse', 'r7_disk_login'];

	return withSessionAuthHints(
		/** @type {Record<string, unknown> & { ok: boolean }} */ ({
			...listingResult,
			do_not_retry: subfoldersOnlyAtRoot ? false : true,
			...(subfoldersOnlyAtRoot ? { agent_stop: false } : {}),
			forbid_followup_tools: forbidAfterList
		}),
		authFromCache
	);
}

/**
 * @param {number} directoryId
 * @param {string} diskSection
 * @returns {string}
 */
function buildListingDedupKey(directoryId, diskSection) {
	return `r7_disk_list_done_${diskSection}_${directoryId}`;
}

/**
 * @param {SkillKeyValueStorage | null} skillStorage
 * @param {number} directoryId
 * @param {string} diskSection
 * @param {Record<string, unknown>} params
 * @returns {(Record<string, unknown> & { ok: boolean }) | null}
 */
function resolveListingDedupHit(skillStorage, directoryId, diskSection, params) {
	if (!skillStorage || params?.force_repeat === true) return null;
	const raw = skillStorage.get(buildListingDedupKey(directoryId, diskSection));
	if (typeof raw !== 'string' || !raw.trim()) return null;
	try {
		const cached = /** @type {Record<string, unknown>} */ (JSON.parse(raw));
		if (cached.ok === false) return null;
		const msg =
			typeof cached.agent_message === 'string' ? cached.agent_message : 'Содержимое папки уже получено.';
		return {
			...cached,
			ok: true,
			already_completed: true,
			do_not_retry: true,
			forbid_followup_tools: [
				'r7_disk_list_directory',
				'list_directory',
				'r7_disk_browse',
				'browse',
				'r7_disk_login'
			],
			agent_message: msg.includes('повтор') ? msg : `${msg} Повторный list_directory не нужен.`
		};
	} catch {
		return null;
	}
}

/**
 * @param {SkillKeyValueStorage | null} skillStorage
 * @param {number} directoryId
 * @param {string} diskSection
 * @param {Record<string, unknown>} result
 */
/**
 * @param {SkillKeyValueStorage | null} skillStorage
 * @param {number} directoryId
 * @param {Record<string, unknown>} params
 * @returns {(Record<string, unknown> & { ok: boolean }) | null}
 */
function resolveListBlockedAfterRead(skillStorage, directoryId, params) {
	if (!skillStorage || params?.force_repeat === true) return null;
	const raw = skillStorage.get(`r7_disk_block_list_after_read_${directoryId}`);
	if (typeof raw !== 'string' || !raw.trim()) return null;
	let fileName = 'файла';
	try {
		const parsed = /** @type {Record<string, unknown>} */ (JSON.parse(raw));
		if (typeof parsed.file_name === 'string' && parsed.file_name.trim()) {
			fileName = parsed.file_name.trim();
		}
	} catch {
		if (raw !== '1') fileName = raw;
	}
	return {
		ok: true,
		already_completed: true,
		directory_id: directoryId,
		do_not_retry: true,
		agent_stop: true,
		agent_message:
			`Содержимое «${fileName}» уже получено через read_content. ` +
			'list_directory не нужен — выведите пользователю content_text из предыдущего ответа.',
		forbid_followup_tools: [
			'r7_disk_list_directory',
			'list_directory',
			'r7_disk_document',
			'read_content',
			'r7_disk_download',
			'download',
			'r7_disk_browse',
			'browse'
		]
	};
}

function persistListingDedup(skillStorage, directoryId, diskSection, result) {
	if (!skillStorage || result.ok === false) return;
	skillStorage.set(
		buildListingDedupKey(directoryId, diskSection),
		JSON.stringify({
			ok: true,
			directory_id: result.directory_id,
			directory_name: result.directory_name,
			disk_section: result.disk_section,
			folders: result.folders,
			documents: result.documents,
			listing_scope_note: result.listing_scope_note,
			agent_message: result.agent_message,
			at: Date.now()
		})
	);
}

/**
 * @param {Record<string, unknown> & { ok: boolean }} result
 * @param {boolean} authFromCache
 * @returns {Record<string, unknown> & { ok: boolean, auth_from_cache: boolean, forbid_followup_tools: string[], session_note?: string }}
 */
function withSessionAuthHints(result, authFromCache) {
	const record = /** @type {Record<string, unknown>} */ (/** @type {unknown} */ (result));
	const existing = Array.isArray(record.forbid_followup_tools)
		? /** @type {string[]} */ (record.forbid_followup_tools)
		: [];
	const merged = [...new Set([...existing, 'r7_disk_login'])];
	return {
		...result,
		auth_from_cache: authFromCache,
		...(authFromCache
			? {
					session_note:
						'Токен из skillStorage. **Не** вызывайте r7_disk_login повторно в этой сессии.',
					forbid_followup_tools: merged
				}
			: { forbid_followup_tools: merged })
	};
}

/**
 * @param {Record<string, unknown>} state
 * @returns {Record<string, unknown>}
 */
function readUserEnv(state) {
	const env = state.environment;
	if (!env || typeof env !== 'object') return {};
	const user = /** @type {Record<string, unknown>} */ (env).user;
	if (!user || typeof user !== 'object') return {};
	return /** @type {Record<string, unknown>} */ (user);
}

/**
 * @param {Record<string, unknown>} state
 * @param {{ base_url?: unknown }} params
 * @param {SkillKeyValueStorage | null} skillStorage
 * @returns {string}
 */
function resolveBaseUrl(state, params, skillStorage) {
	const userEnv = readUserEnv(state);
	const fromParam = typeof params?.base_url === 'string' ? params.base_url.trim() : '';
	if (fromParam) return fromParam.replace(/\/+$/, '');
	if (skillStorage) {
		const cached = skillStorage.get('r7_disk_base_url');
		if (typeof cached === 'string' && cached.trim()) {
			return cached.trim().replace(/\/+$/, '');
		}
	}
	return pickString('', userEnv.R7_DISK_BASE_URL).replace(/\/+$/, '');
}

/**
 * @param {unknown} primary
 * @param {unknown} fallback
 * @returns {string}
 */
function pickString(primary, fallback) {
	if (typeof primary === 'string' && primary.trim()) return primary.trim();
	if (typeof fallback === 'string' && fallback.trim()) return fallback.trim();
	return '';
}

const WEB_SECTION_PATHS = {
	docs: 'docs',
	'shared-to-me': 'shared_to_me',
	shared_to_me: 'shared_to_me',
	'shared-access': 'shared_access',
	shared_access: 'shared_access',
	favorites: 'favorites',
	common: 'common',
	'recycle-bin': 'recycle_bin',
	recycle_bin: 'recycle_bin',
	recent: 'recent',
	filedepot: 'file_depot',
	file_depot: 'file_depot'
};

/**
 * @param {{
 *   params: Record<string, unknown>,
 *   baseUrl: string,
 *   authToken: string,
 *   skillStorage: SkillKeyValueStorage | null,
 *   userEnv: Record<string, unknown>
 * }} ctx
 */
async function resolveListingDirectoryId(ctx) {
	const { params, baseUrl, authToken, skillStorage, userEnv } = ctx;
	const fromLoginParam = parsePositiveId(params.my_documents_directory_id);
	if (fromLoginParam != null) {
		return { ok: true, directory_id: fromLoginParam, disk_section: 'docs' };
	}
	const webParsed = parseWebDiskUrl(params.web_url);
	const section =
		normalizeDiskSection(params.disk_section) ??
		webParsed?.section ??
		'docs';

	const explicitId = parsePositiveId(params.directory_id) ?? webParsed?.directory_id;
	if (explicitId != null) {
		return { ok: true, directory_id: explicitId, disk_section: section };
	}

	const stored = readRootsFromStorage(skillStorage);
	let personalRootId = stored.personalRootId;
	if (personalRootId == null) {
		const resolved = await resolvePersonalRootQuick(baseUrl, authToken, userEnv, skillStorage);
		personalRootId = resolved.personalRootId;
		if (personalRootId != null && skillStorage) {
			skillStorage.set('r7_disk_my_documents_directory_id', String(personalRootId));
		}
	}

	const sectionRoots = stored.sectionRoots;
	const sectionId =
		section === 'docs'
			? personalRootId
			: typeof sectionRoots[section] === 'number'
				? sectionRoots[section]
				: null;

	if (sectionId != null) {
		return { ok: true, directory_id: sectionId, disk_section: section };
	}

	if (section !== 'docs') {
		return {
			ok: false,
			error: `Раздел «${section}» не привязан к API id. Сначала r7_disk_login или укажите directory_id / web_url.`
		};
	}

	return {
		ok: false,
		error:
			'Не удалось определить «Мои документы». Сначала r7_disk_login; передайте my_documents_directory_id или directory_id из ответа login.',
		hint: 'Для списка всех файлов предпочтительнее r7_disk_browse с my_documents_directory_id.'
	};
}

/**
 * @param {unknown} value
 * @returns {number | null}
 */
function parsePositiveId(value) {
	if (typeof value === 'number' && Number.isFinite(value) && value > 0) return value;
	if (typeof value === 'string' && value.trim()) {
		const parsed = Number(value.trim());
		if (Number.isFinite(parsed) && parsed > 0) return parsed;
	}
	return null;
}

function extractUrlPathname(url) {
	const trimmed = url.trim();
	const fromFull = trimmed.match(/^https?:\/\/[^/?#]+(\/[^?#]*)?/i);
	if (fromFull) return fromFull[1] || '/';
	if (trimmed.startsWith('/')) {
		const noQuery = trimmed.split('?')[0].split('#')[0];
		return noQuery || '/';
	}
	return trimmed;
}

function parseWebDiskUrl(url) {
	if (typeof url !== 'string' || !url.trim()) return null;
	const trimmed = url.trim();
	const pathname = extractUrlPathname(trimmed);
	if (!pathname) return null;
	const match = pathname.match(
		/^\/(docs|shared-to-me|shared-access|favorites|common|recycle-bin|recent|fileDepot|filedepot)(?:\/(\d+))?\/?$/i
	);
	if (!match) return null;
	const rawSection = match[1].toLowerCase();
	const sectionKey =
		rawSection === 'filedepot' ? 'file_depot' : rawSection.replace(/-/g, '_');
	const section = WEB_SECTION_PATHS[sectionKey] ?? WEB_SECTION_PATHS[rawSection];
	if (!section) return null;
	const idPart = match[2];
	const directoryId =
		idPart && Number.isFinite(Number(idPart)) && Number(idPart) > 0
			? Math.trunc(Number(idPart))
			: null;
	return { section, directory_id: directoryId };
}

function normalizeDiskSection(value) {
	if (typeof value !== 'string' || !value.trim()) return null;
	const key = value.trim().toLowerCase().replace(/-/g, '_');
	return WEB_SECTION_PATHS[key] ?? null;
}

/**
 * @param {SkillKeyValueStorage | null} skillStorage
 * @returns {{
 *   personalRootId: number | null,
 *   sectionRoots: Record<string, unknown>,
 *   storageState: string | null,
 *   createTarget: unknown
 * }}
 */
function readRootsFromStorage(skillStorage) {
	if (!skillStorage) {
		return {
			personalRootId: null,
			sectionRoots: /** @type {Record<string, unknown>} */ ({}),
			storageState: null,
			createTarget: null
		};
	}
	let personalRootId = parsePositiveId(skillStorage.get('r7_disk_my_documents_directory_id'));
	if (personalRootId == null) {
		personalRootId = pickPersonalRootFromAccessibleRoots(skillStorage);
	}
	/** @type {Record<string, unknown>} */
	let sectionRoots = {};
	const sectionRaw = skillStorage.get('r7_disk_section_roots');
	if (typeof sectionRaw === 'string' && sectionRaw.trim()) {
		try {
			const parsed = JSON.parse(sectionRaw);
			if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
				sectionRoots = /** @type {Record<string, unknown>} */ (parsed);
			}
		} catch {
			sectionRoots = {};
		}
	}
	const storageStateRaw = skillStorage.get('r7_disk_storage_state');
	const storageState = typeof storageStateRaw === 'string' ? storageStateRaw : null;
	let createTarget = null;
	const createRaw = skillStorage.get('r7_disk_create_target');
	if (typeof createRaw === 'string' && createRaw.trim()) {
		try {
			createTarget = JSON.parse(createRaw);
		} catch {
			createTarget = null;
		}
	}
	return { personalRootId, sectionRoots, storageState, createTarget };
}

/**
 * @param {SkillKeyValueStorage | null} skillStorage
 * @returns {number | null}
 */
function pickPersonalRootFromAccessibleRoots(skillStorage) {
	if (!skillStorage) return null;
	const raw = skillStorage.get('r7_disk_accessible_roots');
	if (typeof raw !== 'string' || !raw.trim()) return null;
	try {
		const roots = JSON.parse(raw);
		if (!Array.isArray(roots)) return null;
		for (const item of roots) {
			if (!item || typeof item !== 'object') continue;
			const record = /** @type {Record<string, unknown>} */ (item);
			const name = typeof record.name === 'string' ? record.name.trim() : '';
			const id = parsePositiveId(record.id);
			if (id != null && /мои\s*документ|my\s*documents/i.test(name)) return id;
		}
	} catch {
		return null;
	}
	return null;
}

const LIST_SCAN_BATCH_SIZE = 12;
const LIST_SCAN_MAX_ID = 256;

/**
 * @param {number} [maxId]
 * @returns {number[]}
 */
function buildListScanIds(maxId = LIST_SCAN_MAX_ID) {
	const limit = Math.max(32, Math.min(maxId, LIST_SCAN_MAX_ID));
	/** @type {number[]} */
	const ids = [];
	for (let i = 2; i <= Math.min(128, limit); i++) ids.push(i);
	for (let i = 129; i <= limit; i++) ids.push(i);
	return ids;
}

/**
 * @param {number[]} ids
 * @param {number} size
 * @returns {number[][]}
 */
function chunkListIds(ids, size) {
	/** @type {number[][]} */
	const out = [];
	for (let i = 0; i < ids.length; i += size) out.push(ids.slice(i, i + size));
	return out;
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {Record<string, unknown>} userEnv
 * @param {SkillKeyValueStorage | null} skillStorage
 */
async function resolvePersonalRootQuick(baseUrl, authToken, userEnv, skillStorage) {
	const fromRoots = pickPersonalRootFromAccessibleRoots(skillStorage);
	if (fromRoots != null) return { personalRootId: fromRoots };

	for (const candidateId of [1, 0]) {
		const entry = await fetchDirectoryEntry(baseUrl, authToken, candidateId);
		if (!entry) continue;
		const entryId = typeof entry.Id === 'number' ? entry.Id : candidateId;
		const name = typeof entry.Name === 'string' ? entry.Name : '';
		if (looksLikeMyDocumentsRoot(entry, name)) {
			return { personalRootId: entryId };
		}
	}

	/** @type {{ id: number, name: string } | null} */
	let fallback = null;
	for (const batch of chunkListIds(buildListScanIds(), LIST_SCAN_BATCH_SIZE)) {
		const fetched = await Promise.all(
			batch.map(async (id) => ({
				id,
				entry: await fetchDirectoryEntry(baseUrl, authToken, id)
			}))
		);
		for (const item of fetched) {
			if (!item.entry) continue;
			const entry = item.entry;
			const name = typeof entry.Name === 'string' ? entry.Name : '';
			const entryId = typeof entry.Id === 'number' ? entry.Id : item.id;
			if (/мои\s*документ|my\s*documents/i.test(name.trim())) {
				return { personalRootId: entryId };
			}
			if (fallback == null && looksLikeMyDocumentsRoot(entry, name)) {
				fallback = { id: entryId, name: name.trim() || `id=${entryId}` };
			}
		}
		if (fallback != null) break;
	}
	if (fallback != null) return { personalRootId: fallback.id };

	const defaultParent = parsePositiveId(userEnv.R7_DISK_DEFAULT_PARENT_DIRECTORY_ID);
	if (defaultParent != null) return { personalRootId: defaultParent };
	return { personalRootId: null };
}

function readParentDirectoryId(entry) {
	const parentRaw =
		entry.Parent && typeof entry.Parent === 'object' ? entry.Parent : null;
	const parent = parentRaw ? /** @type {Record<string, unknown>} */ (parentRaw) : null;
	if (parent && typeof parent.Id === 'number') return parent.Id;
	if (typeof entry.ParentId === 'number') return entry.ParentId;
	return null;
}

function looksLikeMyDocumentsRoot(entry, name) {
	const parentId = readParentDirectoryId(entry);
	if (parentId == null || parentId === 0) {
		return !/^(общ|common|shared|корзин|избран|ладкрафт)/i.test(name.trim());
	}
	return /мои\s*документ|my\s*documents|^documents$/i.test(name.trim());
}

async function buildParentChain(baseUrl, authToken, directoryId) {
	/** @type {Array<{ id: number, name: string }>} */
	const chain = [];
	let currentId = directoryId;
	const visited = new Set();
	while (currentId > 0 && !visited.has(currentId)) {
		visited.add(currentId);
		const entry = await fetchDirectoryEntry(baseUrl, authToken, currentId);
		if (!entry) break;
		const entryId = typeof entry.Id === 'number' ? entry.Id : currentId;
		const name = typeof entry.Name === 'string' ? entry.Name.trim() : `id=${entryId}`;
		chain.unshift({ id: entryId, name });
		const parentId = readParentDirectoryId(entry);
		if (parentId == null || parentId === 0) break;
		currentId = parentId;
	}
	return chain;
}

function isUnderPersonalRoot(personalRootId, directoryId, parentChain) {
	if (personalRootId == null) return false;
	if (directoryId === personalRootId) return true;
	return parentChain.some((c) => c.id === personalRootId);
}

/**
 * @param {number | null} parentId
 * @param {string | null} parentName
 * @param {Array<{ id: number, name: string }>} parentChain
 * @returns {{ id: number, name: string } | null}
 */
function inferPersonalRootFromListing(parentId, parentName, parentChain) {
	if (parentId != null && parentName && looksLikeMyDocumentsName(parentName)) {
		return { id: parentId, name: parentName.trim() };
	}
	if (parentChain.length > 0) {
		const top = parentChain[0];
		if (top && looksLikeMyDocumentsName(top.name)) {
			return { id: top.id, name: top.name };
		}
	}
	return null;
}

/**
 * @param {string} name
 * @returns {boolean}
 */
function looksLikeMyDocumentsName(name) {
	return /мои\s*документ|my\s*documents|^documents$/i.test(String(name).trim());
}

/**
 * @param {SkillKeyValueStorage | null} skillStorage
 * @param {number} personalRootId
 * @param {string} [directoryName]
 */
function persistPersonalRootToStorage(skillStorage, personalRootId, directoryName) {
	if (!skillStorage || personalRootId == null) return;
	skillStorage.set('r7_disk_my_documents_directory_id', String(personalRootId));
	skillStorage.set('r7_disk_section_roots', JSON.stringify({ docs: personalRootId }));
	skillStorage.set('r7_disk_storage_state', 'personal_with_content');
	skillStorage.set('r7_disk_create_target', '');
}


function buildWebUrlHint(section, directoryId) {
	const pathMap = {
		docs: 'docs',
		shared_to_me: 'shared-to-me',
		shared_access: 'shared-access',
		favorites: 'favorites',
		common: 'common',
		recycle_bin: 'recycle-bin',
		recent: 'recent',
		file_depot: 'fileDepot'
	};
	const path = pathMap[section] ?? 'docs';
	return `/${path}/${directoryId}`;
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {number} directoryId
 * @returns {Promise<Record<string, unknown> | null>}
 */
async function fetchDirectoryEntry(baseUrl, authToken, directoryId) {
	const url = `${baseUrl}/api/v1/DocumentDirectory/Get?id=${encodeURIComponent(String(directoryId))}`;
	let response;
	try {
		response = await fetch(url, {
			method: 'GET',
			headers: { 'Content-Type': 'application/json', Authorization: authToken }
		});
	} catch {
		return null;
	}
	if (!response.ok) return null;
	const rawText = await readUtf8Text(response);
	try {
		const payload = rawText ? JSON.parse(rawText) : [];
		const entries = Array.isArray(payload) ? payload : [payload];
		const entry = entries.find((item) => item && typeof item === 'object');
		return entry && typeof entry === 'object' ? /** @type {Record<string, unknown>} */ (entry) : null;
	} catch {
		return null;
	}
}

/**
 * @param {string} baseUrl
 * @param {string} login
 * @param {string} password
 * @param {SkillKeyValueStorage | null} skillStorage
 */
async function loginInline(baseUrl, login, password, skillStorage) {
	if (!login || !password) {
		return { ok: false, error: 'Нет auth_token и не заданы R7_DISK_LOGIN/R7_DISK_PASSWORD для авто-login.' };
	}
	const url = `${baseUrl}/api/v2/auth/Login`;
	const response = await fetch(url, {
		method: 'POST',
		headers: { 'Content-Type': 'application/json; charset=utf-8' },
		body: JSON.stringify({ Login: login, Password: password })
	});
	const rawText = await readUtf8Text(response);
	let payload;
	try {
		payload = rawText ? JSON.parse(rawText) : {};
	} catch {
		return { ok: false, error: `Login: ответ не JSON (HTTP ${response.status}).` };
	}
	if (!response.ok) {
		return { ok: false, error: `Login HTTP ${response.status}: ${truncate(rawText, 300)}` };
	}
	const authToken = payload?.Response?.Data?.Tokens?.AuthToken;
	if (typeof authToken !== 'string' || !authToken) {
		return { ok: false, error: 'Login: AuthToken не найден.' };
	}
	if (skillStorage) {
		skillStorage.set('r7_disk_auth_token', authToken);
		skillStorage.set('r7_disk_base_url', baseUrl);
	}
	return { ok: true, auth_token: authToken };
}

/**
 * @typedef {Object} SkillKeyValueStorage
 * @property {(key: string) => unknown} get
 * @property {(key: string, value: string) => void} set
 */

/**
 * @param {Record<string, unknown>} state
 * @returns {SkillKeyValueStorage | null}
 */
function resolveSkillStorage(state) {
	const caps = state.capabilities;
	if (!caps || typeof caps !== 'object') return null;
	const record = /** @type {Record<string, unknown>} */ (caps);
	const raw = record.skillStorage ?? record.storage ?? record['key-value-storage'];
	if (!raw || typeof raw !== 'object') return null;
	const kv = /** @type {{ get?: unknown; set?: unknown }} */ (raw);
	if (typeof kv.get !== 'function' || typeof kv.set !== 'function') return null;
	return /** @type {SkillKeyValueStorage} */ (raw);
}

/**
 * @param {unknown} children
 * @returns {Array<Record<string, unknown>>}
 */
function normalizeFolderList(children) {
	if (!Array.isArray(children)) return [];
	return children
		.filter((item) => item && typeof item === 'object')
		.map((item) => ({
			Id: item.Id,
			Name: item.Name,
			ParentId: item.ParentId,
			Type: item.Type,
			Size: item.Size,
			Timestamp: item.Timestamp,
			IsShared: item.IsShared
		}));
}

/**
 * @param {unknown} documents
 * @returns {Array<Record<string, unknown>>}
 */
function normalizeDocumentList(documents) {
	if (!Array.isArray(documents)) return [];
	return documents
		.filter((item) => item && typeof item === 'object')
		.map((item) => {
			const docId = typeof item.Id === 'number' ? item.Id : null;
			const ownerDirId =
				typeof item.DirectoryId === 'number'
					? item.DirectoryId
					: typeof item.ParentId === 'number'
						? item.ParentId
						: null;
			const docName = typeof item.Name === 'string' ? item.Name : '';
			const isShared = item.IsShared === true || Boolean(item.Author);
			/** @type {Record<string, unknown>} */
			const row = {
				Id: docId,
				document_id: docId,
				Name: docName,
				DirectoryId: ownerDirId,
				owner_directory_id: ownerDirId,
				ParentId: item.ParentId,
				MimeType: item.MimeType,
				Size: item.Size,
				Date: item.Date,
				Timestamp: item.Timestamp,
				IsShared: item.IsShared,
				FileId: item.FileId,
				Author: extractDocumentAuthor(item)
			};
			if (isShared && docId != null && docName) {
				row.shared_edit_example = {
					operation: 'prepend',
					document_id: docId,
					name: docName,
					directory_id: ownerDirId,
					content_text: '…'
				};
			}
			return row;
		});
}

/**
 * @param {Array<Record<string, unknown>>} documents
 * @param {number} directoryId
 * @returns {Array<Record<string, unknown>>}
 */
const VIRTUAL_DISK_SECTIONS = new Set([
	'shared_to_me',
	'shared_access',
	'common',
	'favorites',
	'recent',
	'recycle_bin',
	'file_depot'
]);

/**
 * Определяет раздел по id корня из login (когда агент передал только directory_id).
 * @param {string} diskSection
 * @param {number} directoryId
 * @param {string} dirName
 * @param {Record<string, unknown>} sectionRoots
 * @returns {string}
 */
function inferEffectiveDiskSection(diskSection, directoryId, dirName, sectionRoots) {
	for (const [section, id] of Object.entries(sectionRoots)) {
		if (typeof id === 'number' && id === directoryId) return section;
	}
	if (/доступно\s*для\s*меня/i.test(dirName)) return 'shared_to_me';
	if (/совместн/i.test(dirName)) return 'shared_access';
	if (/^общ/i.test(dirName)) return 'common';
	if (/избран/i.test(dirName)) return 'favorites';
	if (/корзин/i.test(dirName)) return 'recycle_bin';
	if (/последн/i.test(dirName)) return 'recent';
	if (/хранилищ/i.test(dirName)) return 'file_depot';
	return diskSection;
}

/**
 * Строгий фильтр DirectoryId только для личного дерева «Мои документы».
 * В «Доступно для меня» и др. API отдаёт файлы с DirectoryId исходной папки владельца.
 * @param {string} diskSection
 * @param {number} directoryId
 * @param {string} dirName
 * @param {Record<string, unknown>} sectionRoots
 * @returns {boolean}
 */
function shouldStrictFilterDocuments(diskSection, directoryId, dirName, sectionRoots) {
	if (VIRTUAL_DISK_SECTIONS.has(diskSection)) return false;
	if (looksLikeVirtualSectionName(dirName)) return false;
	for (const [section, id] of Object.entries(sectionRoots)) {
		if (section !== 'docs' && typeof id === 'number' && id === directoryId) return false;
	}
	return true;
}

/**
 * @param {string} dirName
 * @returns {boolean}
 */
function looksLikeVirtualSectionName(dirName) {
	return /^(доступно\s*для\s*меня|совместн|общ|избран|корзин|последн|хранилищ)/i.test(
		dirName.trim()
	);
}

/**
 * @param {Record<string, unknown>} item
 * @returns {string | null}
 */
function extractDocumentAuthor(item) {
	if (typeof item.Author === 'string' && item.Author.trim()) return item.Author.trim();
	if (item.Author && typeof item.Author === 'object') {
		const author = /** @type {Record<string, unknown>} */ (item.Author);
		if (typeof author.DisplayName === 'string' && author.DisplayName.trim()) {
			return author.DisplayName.trim();
		}
		const parts = [author.Surname, author.FirstName, author.Name]
			.filter((p) => typeof p === 'string' && p.trim())
			.map((p) => /** @type {string} */ (p).trim());
		if (parts.length > 0) return parts.join(' ');
	}
	for (const key of ['CreatedBy', 'Owner', 'User']) {
		const value = item[key];
		if (typeof value === 'string' && value.trim()) return value.trim();
		if (value && typeof value === 'object') {
			const record = /** @type {Record<string, unknown>} */ (value);
			if (typeof record.DisplayName === 'string' && record.DisplayName.trim()) {
				return record.DisplayName.trim();
			}
			if (typeof record.Name === 'string' && record.Name.trim()) return record.Name.trim();
		}
	}
	if (typeof item.CreatedByName === 'string' && item.CreatedByName.trim()) {
		return item.CreatedByName.trim();
	}
	return null;
}

/**
 * @param {Array<Record<string, unknown>>} documents
 * @param {number} directoryId
 * @returns {Array<Record<string, unknown>>}
 */
function filterDocumentsForDirectory(documents, directoryId) {
	return documents.filter((doc) => documentBelongsToDirectory(doc, directoryId));
}

/**
 * @param {Record<string, unknown>} doc
 * @param {number} directoryId
 * @returns {boolean}
 */
function documentBelongsToDirectory(doc, directoryId) {
	const docDirId = typeof doc.DirectoryId === 'number' ? doc.DirectoryId : null;
	if (docDirId != null) return docDirId === directoryId;
	const parentId = typeof doc.ParentId === 'number' ? doc.ParentId : null;
	if (parentId != null) return parentId === directoryId;
	return true;
}

/**
 * @param {{ text: () => Promise<string> }} response
 * @returns {Promise<string>}
 */
async function readUtf8Text(response) {
	return response.text();
}

/**
 * @param {unknown} value
 * @returns {string}
 */
function errorMessage(value) {
	return value instanceof Error ? value.message : String(value);
}

/**
 * @param {string} text
 * @param {number} max
 * @returns {string}
 */
function truncate(text, max) {
	if (text.length <= max) return text;
	return `${text.slice(0, max)}…`;
}

/**
 * Подсказка агенту: не выдумывать данные вне полей ответа tool.
 * @template T
 * @param {T} fields
 * @param {string[]} citeOnlyFields
 * @returns {T}
 */
function withFactualCitation(fields, citeOnlyFields) {
	const record = /** @type {Record<string, unknown>} */ (/** @type {unknown} */ (fields));
	const msg = typeof record.agent_message === 'string' ? record.agent_message : '';
	const hint = ` Цитируй только ${citeOnlyFields.join(', ')} — не выдумывай.`;
	return /** @type {T} */ ({
		...fields,
		do_not_invent_content: true,
		cite_only_fields: citeOnlyFields,
		agent_message: msg.includes('не выдумывай') ? msg : msg + hint
	});
}

/**
 * Recursively browse R7-Disk directory tree up to max_depth.
 * @param {Record<string, unknown>} state
 * @param {{
 *   directory_id?: unknown,
 *   disk_section?: unknown,
 *   web_url?: unknown,
 *   max_depth?: unknown,
 *   auth_token?: unknown,
 *   base_url?: unknown,
 *   login?: unknown,
 *   password?: unknown
 * }} params
 */
async function handler(state, params) {
	const userEnv = readUserEnv(state);
	const skillStorage = resolveSkillStorage(state);

	const baseUrl = resolveBaseUrl(state, params, skillStorage);
	const login = pickString(params?.login, userEnv.R7_DISK_LOGIN);
	const password = pickString(params?.password, userEnv.R7_DISK_PASSWORD);
	const maxDepth = resolveMaxDepth(params?.max_depth);

	if (!baseUrl) {
		return { ok: false, tree: null, error: 'Не задан R7_DISK_BASE_URL.' };
	}

	let authToken = typeof params?.auth_token === 'string' ? params.auth_token.trim() : '';
	if (!authToken && skillStorage) {
		const cached = skillStorage.get('r7_disk_auth_token');
		if (typeof cached === 'string' && cached.trim()) authToken = cached.trim();
	}
	if (!authToken) {
		const loginResult = await loginInline(baseUrl, login, password, skillStorage);
		if (!loginResult.ok) return { ok: false, tree: null, error: loginResult.error };
		authToken = loginResult.auth_token;
	}

	const resolved = await resolveBrowseRoot({
		params,
		baseUrl,
		authToken,
		skillStorage,
		userEnv
	});
	if (!resolved.ok) {
		return { ok: false, tree: null, error: resolved.error };
	}
	const myDocumentsId = resolved.personal_root_id;
	const diskSection = resolved.disk_section;

	const folderPath =
		typeof params?.folder_path === 'string' ? params.folder_path.trim() : '';
	const folderName =
		typeof params?.folder_name === 'string' ? params.folder_name.trim() : '';
	const explicitDirectoryId = parsePositiveId(params?.directory_id);
	const webParsed = parseWebDiskUrl(params?.web_url);
	const webDirectoryId = webParsed?.directory_id ?? null;

	let directoryId = explicitDirectoryId ?? webDirectoryId ?? resolved.directory_id;
	let resolvedFromName = false;

	if ((folderPath || folderName) && myDocumentsId == null) {
		return {
			ok: false,
			tree: null,
			error:
				'Для поиска папки по имени нужен личный корень. Сначала r7_disk_login или укажите web_url / directory_id.'
		};
	}
	if (directoryId == null) {
		return {
			ok: false,
			tree: null,
			error: 'Не определён каталог для обхода. Выполните r7_disk_login или передайте web_url.'
		};
	}

	if (folderPath) {
		const resolved = await resolveDirectoryByPath(
			baseUrl,
			authToken,
			myDocumentsId,
			folderPath
		);
		if (resolved == null) {
			return {
				ok: false,
				tree: null,
				error: `Папка по пути «${folderPath}» не найдена под «Мои документы».`
			};
		}
		directoryId = resolved;
		resolvedFromName = true;
	} else if (folderName && explicitDirectoryId == null) {
		const resolved = await findDirectoryIdByName(
			baseUrl,
			authToken,
			myDocumentsId,
			folderName
		);
		if (resolved == null) {
			return {
				ok: false,
				tree: null,
				error: `Папка «${folderName}» не найдена в «Мои документы». Проверьте имя или укажите folder_path.`
			};
		}
		directoryId = resolved;
		resolvedFromName = true;
	}

	try {
		const tree = await fetchDirectoryNode(baseUrl, authToken, directoryId, maxDepth, 1);
		const flat = flattenTree(/** @type {Record<string, unknown>} */ (tree), '');
		const rootName = typeof tree.name === 'string' ? tree.name : '';
		const rootId = typeof tree.id === 'number' ? tree.id : directoryId;
		const treeText = formatTreeText(/** @type {Record<string, unknown>} */ (tree));
		const parentChain = await buildParentChain(baseUrl, authToken, rootId);
		const stored = readRootsFromStorage(skillStorage);
		const isPersonalTree = isUnderPersonalRoot(myDocumentsId, rootId, parentChain);
		const scopeWarning =
			myDocumentsId != null && !isPersonalTree && diskSection === 'docs'
				? 'Каталог вне личного «Мои документы» — возможно общий или расшаренный.'
				: '';
		persistBrowseDocumentsIndex(skillStorage, flat.documents);
		return withFactualCitation(
			{
				ok: true,
				tree,
				tree_text: treeText,
				all_documents: flat.documents,
				all_folders: flat.folders,
				total_documents: flat.documents.length,
				total_folders: flat.folders.length,
				max_depth: maxDepth,
				browse_root_id: rootId,
				browse_root_name: rootName,
				disk_section: diskSection,
				parent_chain: parentChain,
				is_personal_tree: isPersonalTree,
				web_url_hint: buildWebUrlHint(diskSection, rootId),
				scope_warning: scopeWarning || undefined,
				resolved_via_folder_name: resolvedFromName,
				browse_scope_note: `Дерево от «${rootName}» (id=${rootId}), глубина ${maxDepth}. Подпапки — в tree / tree_text; все файлы — all_documents.`,
				agent_message: `Дерево папок от «${rootName}» (id=${rootId}): ${flat.folders.length} папок, ${flat.documents.length} файлов в обходе. Покажите пользователю tree_text.`,
				do_not_retry: true,
				forbid_followup_tools: [
					'r7_disk_browse',
					'browse',
					'r7_disk_list_directory',
					'list_directory'
				],
				api_base_url: baseUrl
			},
			['tree_text', 'all_documents', 'all_folders', 'browse_scope_note']
		);
	} catch (err) {
		return { ok: false, tree: null, error: errorMessage(err) };
	}
}

/**
 * Собирает плоский список файлов и папок из дерева browse.
 * @param {Record<string, unknown>} node
 * @param {string} pathPrefix
 * @returns {{ documents: Array<Record<string, unknown>>, folders: Array<Record<string, unknown>> }}
 */
/**
 * @param {string} fileName
 * @returns {string}
 */
function browseDocumentNameKey(fileName) {
	return fileName.trim().toLowerCase();
}

/**
 * @param {SkillKeyValueStorage | null} skillStorage
 * @param {Array<Record<string, unknown>>} documents
 */
function persistBrowseDocumentsIndex(skillStorage, documents) {
	if (!skillStorage || !Array.isArray(documents)) return;
	for (const doc of documents) {
		if (!doc || typeof doc !== 'object') continue;
		const name = typeof doc.name === 'string' ? doc.name.trim() : '';
		const documentId = parsePositiveId(doc.id);
		const directoryId = parsePositiveId(doc.directory_id);
		if (!name || documentId == null || directoryId == null) continue;
		const payload = JSON.stringify({
			document_id: documentId,
			directory_id: directoryId,
			file_name: name,
			updated_at: Date.now()
		});
		skillStorage.set(`r7_disk_doc_id_${directoryId}_${browseDocumentNameKey(name)}`, payload);
		skillStorage.set(`r7_disk_last_browse_doc_${browseDocumentNameKey(name)}`, payload);
	}
}

function flattenTree(node, pathPrefix) {
	const name = typeof node.name === 'string' ? node.name : '';
	const currentPath = pathPrefix ? `${pathPrefix}/${name}` : name;
	const dirId = typeof node.id === 'number' ? node.id : null;

	/** @type {Array<Record<string, unknown>>} */
	const documents = [];
	/** @type {Array<Record<string, unknown>>} */
	const folders = [];

	if (dirId != null && name) {
		folders.push({ id: dirId, name, path: currentPath || name });
	}

	const docs = Array.isArray(node.documents) ? node.documents : [];
	for (const d of docs) {
		if (!d || typeof d !== 'object') continue;
		const doc = /** @type {Record<string, unknown>} */ (d);
		documents.push({
			id: doc.id,
			name: doc.name,
			mimeType: doc.mimeType,
			size: doc.size,
			folder_path: currentPath || name,
			directory_id: dirId
		});
	}

	const childFolders = Array.isArray(node.folders) ? node.folders : [];
	for (const child of childFolders) {
		if (!child || typeof child !== 'object') continue;
		const folder = /** @type {Record<string, unknown>} */ (child);
		if (folder.truncated === true) {
			const childName = typeof folder.name === 'string' ? folder.name : '';
			folders.push({
				id: folder.id,
				name: childName,
				path: currentPath ? `${currentPath}/${childName}` : childName,
				truncated: true
			});
			continue;
		}
		const sub = flattenTree(folder, currentPath);
		documents.push(...sub.documents);
		folders.push(...sub.folders);
	}

	return { documents, folders };
}

/**
 * ASCII-дерево для ответа агенту (копировать в чат как есть).
 * @param {Record<string, unknown>} node
 * @param {string} indent
 * @returns {string}
 */
function formatTreeText(node, indent = '') {
	const name = typeof node.name === 'string' ? node.name : '?';
	const folderCount =
		typeof node.folderCount === 'number' ? node.folderCount : 0;
	const documentCount =
		typeof node.documentCount === 'number' ? node.documentCount : 0;
	/** @type {string[]} */
	const lines = [
		`${indent}${name}/ (${folderCount} подпапок, ${documentCount} файлов на этом уровне)`
	];

	const docs = Array.isArray(node.documents) ? node.documents : [];
	for (const d of docs) {
		if (!d || typeof d !== 'object') continue;
		const doc = /** @type {Record<string, unknown>} */ (d);
		const docName = typeof doc.name === 'string' ? doc.name : '?';
		const size = typeof doc.size === 'number' ? doc.size : 0;
		lines.push(`${indent}  [файл] ${docName} (${size} байт)`);
	}

	const childFolders = Array.isArray(node.folders) ? node.folders : [];
	for (const child of childFolders) {
		if (!child || typeof child !== 'object') continue;
		const folder = /** @type {Record<string, unknown>} */ (child);
		if (folder.truncated === true) {
			const childName = typeof folder.name === 'string' ? folder.name : '?';
			lines.push(`${indent}  ${childName}/ … (глубже лимита обхода)`);
			continue;
		}
		lines.push(formatTreeText(folder, `${indent}  `));
	}

	return lines.join('\n');
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {number} rootId
 * @param {string} pathStr
 * @returns {Promise<number | null>}
 */
async function resolveDirectoryByPath(baseUrl, authToken, rootId, pathStr) {
	const segments = pathStr
		.split('/')
		.map((s) => s.trim())
		.filter(Boolean);
	let currentId = rootId;
	for (const segment of segments) {
		const entry = await fetchDirectoryEntryForBrowse(baseUrl, authToken, currentId);
		if (!entry) return null;
		const children = Array.isArray(entry.Children) ? entry.Children : [];
		const match = children.find(
			(c) =>
				c &&
				typeof c === 'object' &&
				typeof c.Name === 'string' &&
				c.Name.trim() === segment
		);
		if (!match || typeof match.Id !== 'number') return null;
		currentId = match.Id;
	}
	return currentId;
}

/**
 * Ищет папку по имени: сначала среди детей root, затем BFS на глубину 4.
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {number} rootId
 * @param {string} folderName
 * @returns {Promise<number | null>}
 */
async function findDirectoryIdByName(baseUrl, authToken, rootId, folderName) {
	const target = folderName.trim();
	/** @type {Array<{ id: number, depth: number }>} */
	const queue = [{ id: rootId, depth: 0 }];
	const visited = new Set();

	while (queue.length > 0) {
		const current = queue.shift();
		if (!current || visited.has(current.id)) continue;
		visited.add(current.id);

		const entry = await fetchDirectoryEntryForBrowse(baseUrl, authToken, current.id);
		if (!entry) continue;

		const children = Array.isArray(entry.Children) ? entry.Children : [];
		for (const child of children) {
			if (!child || typeof child !== 'object' || typeof child.Id !== 'number') continue;
			const name = typeof child.Name === 'string' ? child.Name.trim() : '';
			if (name === target) return child.Id;
			if (current.depth < 4) {
				queue.push({ id: child.Id, depth: current.depth + 1 });
			}
		}
	}
	return null;
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {number} directoryId
 * @param {number} maxDepth
 * @param {number} currentDepth
 */
async function fetchDirectoryNode(baseUrl, authToken, directoryId, maxDepth, currentDepth) {
	const url = `${baseUrl}/api/v1/DocumentDirectory/Get?id=${encodeURIComponent(String(directoryId))}`;
	const response = await fetch(url, {
		method: 'GET',
		headers: {
			'Content-Type': 'application/json',
			Authorization: authToken
		}
	});
	const rawText = await readUtf8Text(response);
	if (!response.ok) {
		throw new Error(`Get id=${directoryId} HTTP ${response.status}: ${truncate(rawText, 200)}`);
	}
	let payload;
	try {
		payload = rawText ? JSON.parse(rawText) : [];
	} catch {
		throw new Error(`Get id=${directoryId}: ответ не JSON.`);
	}
	const entries = Array.isArray(payload) ? payload : [payload];
	const entry = entries.find((item) => item && typeof item === 'object') ?? entries[0];
	if (!entry || typeof entry !== 'object') {
		throw new Error(`Get id=${directoryId}: пустой ответ.`);
	}

	/** @type {Array<Record<string, unknown>>} */
	const childFolders = [];
	const rawChildren = Array.isArray(entry.Children) ? entry.Children : [];
	if (currentDepth < maxDepth) {
		for (const child of rawChildren) {
			if (!child || typeof child !== 'object' || typeof child.Id !== 'number') continue;
			const subtree = await fetchDirectoryNode(
				baseUrl,
				authToken,
				child.Id,
				maxDepth,
				currentDepth + 1
			);
			childFolders.push(subtree);
		}
	} else {
		for (const child of rawChildren) {
			if (!child || typeof child !== 'object') continue;
			childFolders.push({
				id: child.Id,
				name: child.Name,
				truncated: true
			});
		}
	}

	const documents = Array.isArray(entry.Documents)
		? entry.Documents.filter((d) => d && typeof d === 'object').map((d) => ({
				id: d.Id,
				name: d.Name,
				mimeType: d.MimeType,
				size: d.Size
			}))
		: [];

	return {
		id: entry.Id,
		name: entry.Name,
		parentId: entry.ParentId,
		folders: childFolders,
		documents,
		documentCount: documents.length,
		folderCount: rawChildren.length
	};
}

/**
 * @param {Record<string, unknown>} state
 * @returns {Record<string, unknown>}
 */
function readUserEnv(state) {
	const env = state.environment;
	if (!env || typeof env !== 'object') return {};
	const user = /** @type {Record<string, unknown>} */ (env).user;
	if (!user || typeof user !== 'object') return {};
	return /** @type {Record<string, unknown>} */ (user);
}

/**
 * @param {Record<string, unknown>} state
 * @param {{ base_url?: unknown }} params
 * @param {SkillKeyValueStorage | null} skillStorage
 * @returns {string}
 */
function resolveBaseUrl(state, params, skillStorage) {
	const userEnv = readUserEnv(state);
	const fromParam = typeof params?.base_url === 'string' ? params.base_url.trim() : '';
	if (fromParam) return fromParam.replace(/\/+$/, '');
	if (skillStorage) {
		const cached = skillStorage.get('r7_disk_base_url');
		if (typeof cached === 'string' && cached.trim()) {
			return cached.trim().replace(/\/+$/, '');
		}
	}
	return pickString('', userEnv.R7_DISK_BASE_URL).replace(/\/+$/, '');
}

/**
 * @param {unknown} primary
 * @param {unknown} fallback
 * @returns {string}
 */
function pickString(primary, fallback) {
	if (typeof primary === 'string' && primary.trim()) return primary.trim();
	if (typeof fallback === 'string' && fallback.trim()) return fallback.trim();
	return '';
}

const WEB_SECTION_PATHS = {
	docs: 'docs',
	'shared-to-me': 'shared_to_me',
	shared_to_me: 'shared_to_me',
	'shared-access': 'shared_access',
	shared_access: 'shared_access',
	favorites: 'favorites',
	common: 'common',
	'recycle-bin': 'recycle_bin',
	recycle_bin: 'recycle_bin',
	recent: 'recent',
	filedepot: 'file_depot',
	file_depot: 'file_depot'
};

async function resolveBrowseRoot(ctx) {
	const { params, baseUrl, authToken, skillStorage, userEnv } = ctx;
	const fromLoginParam = parsePositiveId(params.my_documents_directory_id);
	if (fromLoginParam != null) {
		return {
			ok: true,
			directory_id: fromLoginParam,
			personal_root_id: fromLoginParam,
			disk_section: 'docs'
		};
	}
	const webParsed = parseWebDiskUrl(params.web_url);
	const section =
		normalizeDiskSection(params.disk_section) ?? webParsed?.section ?? 'docs';
	const stored = readRootsFromStorage(skillStorage);
	let personalRootId = stored.personalRootId;
	if (personalRootId == null) {
		const quick = await resolvePersonalRootQuick(baseUrl, authToken, userEnv, skillStorage);
		personalRootId = quick.personalRootId;
		if (personalRootId != null && skillStorage) {
			skillStorage.set('r7_disk_my_documents_directory_id', String(personalRootId));
		}
	}
	const sectionId =
		section === 'docs'
			? personalRootId
			: typeof stored.sectionRoots[section] === 'number'
				? stored.sectionRoots[section]
				: null;
	if (sectionId == null && parsePositiveId(params.directory_id) == null && !webParsed?.directory_id) {
		return {
			ok: false,
			error:
				'Не удалось определить корень browse. Сначала r7_disk_login или передайте my_documents_directory_id / directory_id из ответа login.',
			hint: 'После login: r7_disk_browse { my_documents_directory_id: <из login> }'
		};
	}
	return {
		ok: true,
		directory_id: sectionId ?? personalRootId,
		personal_root_id: personalRootId,
		disk_section: section
	};
}

/**
 * @param {unknown} value
 * @returns {number | null}
 */
function parsePositiveId(value) {
	if (typeof value === 'number' && Number.isFinite(value) && value > 0) return value;
	if (typeof value === 'string' && value.trim()) {
		const parsed = Number(value.trim());
		if (Number.isFinite(parsed) && parsed > 0) return parsed;
	}
	return null;
}

function extractUrlPathname(url) {
	const trimmed = url.trim();
	const fromFull = trimmed.match(/^https?:\/\/[^/?#]+(\/[^?#]*)?/i);
	if (fromFull) return fromFull[1] || '/';
	if (trimmed.startsWith('/')) {
		const noQuery = trimmed.split('?')[0].split('#')[0];
		return noQuery || '/';
	}
	return trimmed;
}

function parseWebDiskUrl(url) {
	if (typeof url !== 'string' || !url.trim()) return null;
	const trimmed = url.trim();
	const pathname = extractUrlPathname(trimmed);
	if (!pathname) return null;
	const match = pathname.match(
		/^\/(docs|shared-to-me|shared-access|favorites|common|recycle-bin|recent|fileDepot|filedepot)(?:\/(\d+))?\/?$/i
	);
	if (!match) return null;
	const rawSection = match[1].toLowerCase();
	const sectionKey =
		rawSection === 'filedepot' ? 'file_depot' : rawSection.replace(/-/g, '_');
	const section = WEB_SECTION_PATHS[sectionKey] ?? WEB_SECTION_PATHS[rawSection];
	if (!section) return null;
	const idPart = match[2];
	const directoryId =
		idPart && Number.isFinite(Number(idPart)) && Number(idPart) > 0
			? Math.trunc(Number(idPart))
			: null;
	return { section, directory_id: directoryId };
}

function normalizeDiskSection(value) {
	if (typeof value !== 'string' || !value.trim()) return null;
	const key = value.trim().toLowerCase().replace(/-/g, '_');
	return WEB_SECTION_PATHS[key] ?? null;
}

function readRootsFromStorage(skillStorage) {
	if (!skillStorage) {
		return { personalRootId: null, sectionRoots: {}, storageState: null, createTarget: null };
	}
	let personalRootId = parsePositiveId(skillStorage.get('r7_disk_my_documents_directory_id'));
	if (personalRootId == null) {
		personalRootId = pickPersonalRootFromAccessibleRoots(skillStorage);
	}
	let sectionRoots = {};
	const sectionRaw = skillStorage.get('r7_disk_section_roots');
	if (typeof sectionRaw === 'string' && sectionRaw.trim()) {
		try {
			sectionRoots = JSON.parse(sectionRaw);
		} catch {
			sectionRoots = {};
		}
	}
	return { personalRootId, sectionRoots, storageState: null, createTarget: null };
}

/**
 * @param {SkillKeyValueStorage | null} skillStorage
 * @returns {number | null}
 */
function pickPersonalRootFromAccessibleRoots(skillStorage) {
	if (!skillStorage) return null;
	const raw = skillStorage.get('r7_disk_accessible_roots');
	if (typeof raw !== 'string' || !raw.trim()) return null;
	try {
		const roots = JSON.parse(raw);
		if (!Array.isArray(roots)) return null;
		for (const item of roots) {
			if (!item || typeof item !== 'object') continue;
			const record = /** @type {Record<string, unknown>} */ (item);
			const name = typeof record.name === 'string' ? record.name.trim() : '';
			const id = parsePositiveId(record.id);
			if (id != null && /мои\s*документ|my\s*documents/i.test(name)) return id;
		}
		for (const item of roots) {
			if (!item || typeof item !== 'object') continue;
			const record = /** @type {Record<string, unknown>} */ (item);
			const id = parsePositiveId(record.id);
			const parentId = record.parent_id;
			const isTop = record.is_top_level === true || parentId == null || parentId === 0;
			const name = typeof record.name === 'string' ? record.name.trim() : '';
			if (id != null && isTop && /мои\s*документ|my\s*documents/i.test(name)) return id;
		}
	} catch {
		return null;
	}
	return null;
}

const BROWSE_SCAN_BATCH_SIZE = 12;
const BROWSE_SCAN_MAX_ID = 256;

/**
 * @param {number} [maxId]
 * @returns {number[]}
 */
function buildBrowseScanIds(maxId = BROWSE_SCAN_MAX_ID) {
	const limit = Math.max(32, Math.min(maxId, BROWSE_SCAN_MAX_ID));
	/** @type {number[]} */
	const ids = [];
	for (let i = 2; i <= Math.min(128, limit); i++) ids.push(i);
	for (let i = 129; i <= limit; i++) ids.push(i);
	return ids;
}

/**
 * @param {number[]} ids
 * @param {number} size
 * @returns {number[][]}
 */
function chunkBrowseIds(ids, size) {
	/** @type {number[][]} */
	const out = [];
	for (let i = 0; i < ids.length; i += size) out.push(ids.slice(i, i + size));
	return out;
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {SkillKeyValueStorage | null} skillStorage
 */
async function resolvePersonalRootQuick(baseUrl, authToken, userEnv, skillStorage) {
	const fromRoots = pickPersonalRootFromAccessibleRoots(skillStorage);
	if (fromRoots != null) return { personalRootId: fromRoots };

	for (const candidateId of [1, 0]) {
		const entry = await fetchDirectoryEntryForBrowse(baseUrl, authToken, candidateId);
		if (!entry) continue;
		const entryId = typeof entry.Id === 'number' ? entry.Id : candidateId;
		const name = typeof entry.Name === 'string' ? entry.Name : '';
		if (looksLikeMyDocumentsRoot(entry, name)) {
			return { personalRootId: entryId };
		}
	}

	/** @type {{ id: number, name: string } | null} */
	let fallback = null;
	for (const batch of chunkBrowseIds(buildBrowseScanIds(), BROWSE_SCAN_BATCH_SIZE)) {
		const fetched = await Promise.all(
			batch.map(async (id) => ({
				id,
				entry: await fetchDirectoryEntryForBrowse(baseUrl, authToken, id)
			}))
		);
		for (const item of fetched) {
			if (!item.entry) continue;
			const entry = item.entry;
			const name = typeof entry.Name === 'string' ? entry.Name : '';
			const entryId = typeof entry.Id === 'number' ? entry.Id : item.id;
			if (/мои\s*документ|my\s*documents/i.test(name.trim())) {
				return { personalRootId: entryId };
			}
			if (fallback == null && looksLikeMyDocumentsRoot(entry, name)) {
				fallback = { id: entryId, name: name.trim() || `id=${entryId}` };
			}
		}
		if (fallback != null) break;
	}
	if (fallback != null) return { personalRootId: fallback.id };

	const defaultParent = parsePositiveId(userEnv.R7_DISK_DEFAULT_PARENT_DIRECTORY_ID);
	if (defaultParent != null) return { personalRootId: defaultParent };
	return { personalRootId: null };
}

function readParentDirectoryId(entry) {
	const parentRaw =
		entry.Parent && typeof entry.Parent === 'object' ? entry.Parent : null;
	const parent = parentRaw ? /** @type {Record<string, unknown>} */ (parentRaw) : null;
	if (parent && typeof parent.Id === 'number') return parent.Id;
	if (typeof entry.ParentId === 'number') return entry.ParentId;
	return null;
}

function looksLikeMyDocumentsRoot(entry, name) {
	const parentId = readParentDirectoryId(entry);
	if (parentId == null || parentId === 0) {
		return !/^(общ|common|shared|корзин|избран|ладкрафт)/i.test(name.trim());
	}
	return /мои\s*документ|my\s*documents|^documents$/i.test(name.trim());
}

async function buildParentChain(baseUrl, authToken, directoryId) {
	/** @type {Array<{ id: number, name: string }>} */
	const chain = [];
	let currentId = directoryId;
	const visited = new Set();
	while (currentId > 0 && !visited.has(currentId)) {
		visited.add(currentId);
		const entry = await fetchDirectoryEntryForBrowse(baseUrl, authToken, currentId);
		if (!entry) break;
		const entryId = typeof entry.Id === 'number' ? entry.Id : currentId;
		const name = typeof entry.Name === 'string' ? entry.Name.trim() : `id=${entryId}`;
		chain.unshift({ id: entryId, name });
		const parentId = readParentDirectoryId(entry);
		if (parentId == null || parentId === 0) break;
		currentId = parentId;
	}
	return chain;
}

function isUnderPersonalRoot(personalRootId, directoryId, parentChain) {
	if (personalRootId == null) return false;
	if (directoryId === personalRootId) return true;
	return parentChain.some((c) => c.id === personalRootId);
}

function buildWebUrlHint(section, directoryId) {
	const pathMap = {
		docs: 'docs',
		shared_to_me: 'shared-to-me',
		shared_access: 'shared-access',
		favorites: 'favorites',
		common: 'common',
		recycle_bin: 'recycle-bin',
		recent: 'recent',
		file_depot: 'fileDepot'
	};
	const path = pathMap[section] ?? 'docs';
	return `/${path}/${directoryId}`;
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {number} directoryId
 * @returns {Promise<Record<string, unknown> | null>}
 */
async function fetchDirectoryEntryForBrowse(baseUrl, authToken, directoryId) {
	const url = `${baseUrl}/api/v1/DocumentDirectory/Get?id=${encodeURIComponent(String(directoryId))}`;
	let response;
	try {
		response = await fetch(url, {
			method: 'GET',
			headers: { 'Content-Type': 'application/json', Authorization: authToken }
		});
	} catch {
		return null;
	}
	if (!response.ok) return null;
	const rawText = await readUtf8Text(response);
	try {
		const payload = rawText ? JSON.parse(rawText) : [];
		const entries = Array.isArray(payload) ? payload : [payload];
		const entry = entries.find((item) => item && typeof item === 'object');
		return entry && typeof entry === 'object' ? /** @type {Record<string, unknown>} */ (entry) : null;
	} catch {
		return null;
	}
}

/** Максимальная глубина рекурсивного обхода (уровни папок). */
const BROWSE_MAX_DEPTH_CAP = 8;

/**
 * @param {unknown} value
 * @returns {number}
 */
function resolveMaxDepth(value) {
	if (typeof value === 'number' && Number.isFinite(value) && value >= 1) {
		return Math.min(Math.floor(value), BROWSE_MAX_DEPTH_CAP);
	}
	if (typeof value === 'string' && value.trim()) {
		const parsed = Number(value.trim());
		if (Number.isFinite(parsed) && parsed >= 1) {
			return Math.min(Math.floor(parsed), BROWSE_MAX_DEPTH_CAP);
		}
	}
	/** По умолчанию — достаточно для типичного дерева «Мои документы» без настройки пользователем. */
	return 5;
}

/**
 * @param {string} baseUrl
 * @param {string} login
 * @param {string} password
 * @param {SkillKeyValueStorage | null} skillStorage
 */
async function loginInline(baseUrl, login, password, skillStorage) {
	if (!login || !password) {
		return { ok: false, error: 'Нет auth_token и не заданы учётные данные для авто-login.' };
	}
	const url = `${baseUrl}/api/v2/auth/Login`;
	const response = await fetch(url, {
		method: 'POST',
		headers: { 'Content-Type': 'application/json; charset=utf-8' },
		body: JSON.stringify({ Login: login, Password: password })
	});
	const rawText = await readUtf8Text(response);
	let payload;
	try {
		payload = rawText ? JSON.parse(rawText) : {};
	} catch {
		return { ok: false, error: `Login: ответ не JSON (HTTP ${response.status}).` };
	}
	if (!response.ok) {
		return { ok: false, error: `Login HTTP ${response.status}: ${truncate(rawText, 300)}` };
	}
	const authToken = payload?.Response?.Data?.Tokens?.AuthToken;
	if (typeof authToken !== 'string' || !authToken) {
		return { ok: false, error: 'Login: AuthToken не найден.' };
	}
	if (skillStorage) {
		skillStorage.set('r7_disk_auth_token', authToken);
		skillStorage.set('r7_disk_base_url', baseUrl);
	}
	return { ok: true, auth_token: authToken };
}

/**
 * @typedef {Object} SkillKeyValueStorage
 * @property {(key: string) => unknown} get
 * @property {(key: string, value: string) => void} set
 */

/**
 * @param {Record<string, unknown>} state
 * @returns {SkillKeyValueStorage | null}
 */
function resolveSkillStorage(state) {
	const caps = state.capabilities;
	if (!caps || typeof caps !== 'object') return null;
	const record = /** @type {Record<string, unknown>} */ (caps);
	const raw = record.skillStorage ?? record.storage ?? record['key-value-storage'];
	if (!raw || typeof raw !== 'object') return null;
	const kv = /** @type {{ get?: unknown; set?: unknown }} */ (raw);
	if (typeof kv.get !== 'function' || typeof kv.set !== 'function') return null;
	return /** @type {SkillKeyValueStorage} */ (raw);
}

/**
 * @param {{ text: () => Promise<string> }} response
 * @returns {Promise<string>}
 */
async function readUtf8Text(response) {
	return response.text();
}

/**
 * @param {unknown} value
 * @returns {string}
 */
function errorMessage(value) {
	return value instanceof Error ? value.message : String(value);
}

/**
 * @param {string} text
 * @param {number} max
 * @returns {string}
 */
function truncate(text, max) {
	if (text.length <= max) return text;
	return `${text.slice(0, max)}…`;
}

/**
 * Подсказка агенту: не выдумывать данные вне полей ответа tool.
 * @template T
 * @param {T} fields
 * @param {string[]} citeOnlyFields
 * @returns {T}
 */
function withFactualCitation(fields, citeOnlyFields) {
	const record = /** @type {Record<string, unknown>} */ (/** @type {unknown} */ (fields));
	const msg = typeof record.agent_message === 'string' ? record.agent_message : '';
	const hint = ` Цитируй только ${citeOnlyFields.join(', ')} — не выдумывай.`;
	return /** @type {T} */ ({
		...fields,
		do_not_invent_content: true,
		cite_only_fields: citeOnlyFields,
		agent_message: msg.includes('не выдумывай') ? msg : msg + hint
	});
}

/**
 * Folder operations on R7-Disk (KS 2024 DocumentDirectory API).
 * @param {Record<string, unknown>} state
 * @param {{
 *   action?: unknown,
 *   parent_directory_id?: unknown,
 *   folder_id?: unknown,
 *   folder_ids?: unknown,
 *   to_directory_id?: unknown,
 *   name?: unknown,
 *   folder_path?: unknown,
 *   rule?: unknown,
 *   auth_token?: unknown,
 *   base_url?: unknown,
 *   login?: unknown,
 *   password?: unknown
 * }} params
 */
/**
 * VM bootstrap может передать аргументы через globalThis.input.
 * @returns {Record<string, unknown> | null}
 */
function readGlobalToolInput() {
	try {
		/** @type {Record<string, unknown>} */
		const g =
			typeof globalThis !== 'undefined'
				? /** @type {Record<string, unknown>} */ (globalThis)
				: {};
		const value = g['input'];
		if (value && typeof value === 'object' && !Array.isArray(value)) {
			return /** @type {Record<string, unknown>} */ (value);
		}
	} catch {
		/* ignore */
	}
	return null;
}

/**
 * @param {unknown} raw
 * @param {Record<string, unknown>} [state]
 * @returns {Record<string, unknown>}
 */
function normalizeToolParams(raw, state) {
	/** @type {Record<string, unknown>} */
	let base = {};
	if (typeof raw === 'string' && raw.trim()) {
		try {
			const parsed = JSON.parse(raw);
			if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
				base = /** @type {Record<string, unknown>} */ (parsed);
			}
		} catch {
			base = {};
		}
	} else if (raw && typeof raw === 'object' && !Array.isArray(raw)) {
		base = /** @type {Record<string, unknown>} */ (raw);
	}
	const nestedKeys = ['input', 'arguments', 'params', 'payload', 'tool_input'];
	for (const key of nestedKeys) {
		const nested = base[key];
		if (nested && typeof nested === 'object' && !Array.isArray(nested)) {
			base = { ...base, .../** @type {Record<string, unknown>} */ (nested) };
		}
	}
	if (state && typeof state === 'object') {
		for (const key of nestedKeys) {
			const nested = state[key];
			if (nested && typeof nested === 'object' && !Array.isArray(nested)) {
				const nestedRecord = /** @type {Record<string, unknown>} */ (nested);
				if (!resolveToolAction(base) && resolveToolAction(nestedRecord)) {
					base = { ...base, ...nestedRecord };
				}
			}
		}
	}
	const globalInput = readGlobalToolInput();
	if (globalInput && (Object.keys(base).length === 0 || !resolveToolAction(base))) {
		base = { ...globalInput, ...base };
	}
	return base;
}

/**
 * @param {Record<string, unknown>} params
 * @returns {string}
 */
function resolveToolAction(params) {
	const candidates = [
		params.operation,
		params.action,
		params.tool_action,
		params['Operation'],
		params['Action']
	];
	for (const value of candidates) {
		if (typeof value === 'string' && value.trim()) {
			return value.trim().toLowerCase();
		}
	}
	return '';
}

async function handler(state, params) {
	const input = normalizeToolParams(params, /** @type {Record<string, unknown>} */ (state));
	const action = resolveToolAction(input);
	if (!action) {
		return {
			ok: false,
			error:
				'Не задан operation (или action). Допустимо: create, move, copy, delete, restore, conflict, rename (справка).',
			debug_received_keys: Object.keys(input),
			debug_raw_param_type: params == null ? 'null' : typeof params
		};
	}

	const userEnv = readUserEnv(state);
	const skillStorage = resolveSkillStorage(state);
	const baseUrl = resolveBaseUrl(state, input, skillStorage);
	const login = pickString(input?.login, userEnv.R7_DISK_LOGIN);
	const password = pickString(input?.password, userEnv.R7_DISK_PASSWORD);

	if (!baseUrl) {
		return { ok: false, error: 'Не задан R7_DISK_BASE_URL.' };
	}

	const authResult = await ensureAuthToken(
		baseUrl,
		login,
		password,
		skillStorage,
		input?.auth_token
	);
	if (!authResult.ok) return { ok: false, error: authResult.error };
	const authToken = authResult.auth_token;

	try {
		switch (action) {
			case 'create':
				return await actionCreate(
					baseUrl,
					authToken,
					input,
					state,
					skillStorage,
					userEnv
				);
			case 'move':
				return await actionMove(baseUrl, authToken, input);
			case 'copy':
				return await actionCopy(baseUrl, authToken, input);
			case 'delete':
				return await actionDelete(baseUrl, authToken, input);
			case 'restore':
				return await actionRestore(baseUrl, authToken, input);
			case 'conflict':
				return await actionConflict(baseUrl, authToken, input);
			case 'rename':
				return actionRenameFolderHelp(input);
			default:
				return {
					ok: false,
					error: `Неизвестный action "${action}". Допустимо: create, move, copy, delete, restore, conflict, rename (справка).`
				};
		}
	} catch (err) {
		return { ok: false, error: errorMessage(err) };
	}
}

/**
 * KS 2024 API не содержит DocumentDirectory/Rename — только справка и обходной путь.
 * @param {Record<string, unknown>} params
 */
function actionRenameFolderHelp(params) {
	const folderId = resolvePositiveId(params?.folder_id);
	const newName = typeof params?.name === 'string' ? params.name.trim() : '';
	return {
		ok: false,
		impossible: true,
		action: 'rename',
		folder_id: folderId,
		new_name: newName || null,
		error:
			'Действие невозможно: переименование папок не поддерживается API Р7-Диска (KS 2024). ' +
			'Переименование доступно только для файлов (r7_disk_document, action rename).'
	};
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {Record<string, unknown>} params
 */
async function actionCreate(baseUrl, authToken, params, state, skillStorage, userEnv) {
	const parentId = await resolveParentDirectoryId(
		baseUrl,
		authToken,
		params,
		skillStorage,
		userEnv
	);
	if (parentId == null) {
		return buildMissingParentError(params, skillStorage, userEnv);
	}

	const folderPathRaw =
		typeof params?.folder_path === 'string' ? params.folder_path.trim() : '';
	const nameRaw = typeof params?.name === 'string' ? params.name.trim() : '';
	const batchNames = resolveFolderNameList(params);
	const segments = folderPathRaw
		? folderPathRaw.split('/').map((s) => s.trim()).filter(Boolean)
		: batchNames.length > 0
			? batchNames
			: nameRaw
				? [nameRaw]
				: [];

	if (segments.length === 0) {
		return {
			ok: false,
			error:
				'Для create укажите name (одна папка), names (массив имён) или folder_path (например "Отчёты/2026/Январь").'
		};
	}

	/** @type {Array<{ name: string, id: number }>} */
	const created = [];
	const isNestedPath = folderPathRaw.length > 0 && segments.length > 1;
	let currentParentId = parentId;

	for (let index = 0; index < segments.length; index++) {
		const segment = segments[index];
		const segmentParentId = isNestedPath ? currentParentId : parentId;
		const result = await postAddSubDirectory(baseUrl, authToken, segmentParentId, segment);
		if (!result.ok) {
			return {
				ok: false,
				error: result.error,
				error_code: result.error_code,
				created_folders: created,
				parent_directory_id: parentId,
				fix_step: result.fix_step,
				api_base_url: baseUrl
			};
		}
		const folderId = result.folder_id;
		if (folderId == null) {
			return {
				ok: false,
				error: `Папка "${segment}" создана, но ID не найден в ответе API.`,
				created_folders: created,
				api_base_url: baseUrl
			};
		}
		created.push({ name: segment, id: folderId });
		if (isNestedPath) {
			currentParentId = folderId;
		}
	}

	const last = created[created.length - 1];
	const batchCount = !folderPathRaw && batchNames.length > 1 ? batchNames.length : 1;
	const agentMessage =
		batchCount > 1
			? `Создано ${created.length} папок в «Мои документы» (родитель id=${parentId}): ${created.map((f) => `«${f.name}» id=${f.id}`).join(', ')}.`
			: `Папка «${last.name}» создана (id=${last.id}, родитель id=${parentId}).`;

	return withFactualCitation(
		{
			ok: true,
			action: 'create',
			folder_id: last.id,
			folder_name: last.name,
			parent_directory_id: parentId,
			created_folders: created,
			agent_message: agentMessage,
			do_not_retry: true,
			forbid_followup_tools: [
				'r7_disk_folder',
				'r7_disk_login',
				'r7_disk_list_directory',
				'list_directory'
			],
			api_base_url: baseUrl
		},
		['created_folders', 'folder_id', 'folder_name', 'agent_message']
	);
}

/**
 * @param {Record<string, unknown>} params
 * @returns {string[]}
 */
function resolveFolderNameList(params) {
	const raw = params?.names;
	if (!Array.isArray(raw)) return [];
	/** @type {string[]} */
	const names = [];
	for (const item of raw) {
		if (typeof item === 'string' && item.trim()) {
			names.push(item.trim());
		}
	}
	return names;
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {Record<string, unknown>} params
 * @param {SkillKeyValueStorage | null} skillStorage
 * @param {Record<string, unknown>} userEnv
 * @returns {Promise<number | null>}
 */
async function resolveParentDirectoryId(baseUrl, authToken, params, skillStorage, userEnv) {
	const direct = resolvePositiveId(params?.parent_directory_id);
	if (direct != null) return direct;

	const fromAlias = resolvePositiveId(params?.my_documents_directory_id);
	if (fromAlias != null) return fromAlias;

	const fromNestedTarget = extractParentFromCreateTarget(params?.create_target);
	if (fromNestedTarget != null) return fromNestedTarget;

	let fromCache = resolveDefaultParentDirectoryId(skillStorage, userEnv);
	if (fromCache != null) return fromCache;

	if (authToken && baseUrl) {
		const discovered = await discoverPersonalRootQuick(baseUrl, authToken);
		if (discovered != null) {
			persistCreateTarget(skillStorage, discovered.id, discovered.name);
			return discovered.id;
		}
	}

	return null;
}

/**
 * @param {unknown} value
 * @returns {number | null}
 */
function extractParentFromCreateTarget(value) {
	if (!value || typeof value !== 'object') return null;
	const target = /** @type {Record<string, unknown>} */ (value);
	return resolvePositiveId(target.parent_directory_id);
}

/**
 * @param {Record<string, unknown>} params
 * @param {SkillKeyValueStorage | null} skillStorage
 * @param {Record<string, unknown>} userEnv
 */
function buildMissingParentError(params, skillStorage, userEnv) {
	const cachedParent = resolveDefaultParentDirectoryId(skillStorage, userEnv);
	const authToken = typeof params?.auth_token === 'string' ? params.auth_token.trim() : '';
	/** @type {Record<string, unknown>} */
	const example = {
		operation: 'create',
		name: 'Имя_папки'
	};
	if (authToken) example.auth_token = authToken;
	if (cachedParent != null) {
		example.parent_directory_id = cachedParent;
	} else {
		example.parent_directory_id = '<create_target.parent_directory_id из r7_disk_login>';
		if (!authToken) {
			example.auth_token = '<auth_token из r7_disk_login>';
		}
	}

	return {
		ok: false,
		error:
			'Не найден родительский каталог. Сначала r7_disk_login, затем create с auth_token и parent_directory_id из ответа.',
		error_code: 'MISSING_PARENT',
		hint:
			'Кэш skillStorage между вызовами tools на платформе может быть недоступен — всегда передавайте auth_token и parent_directory_id из ответа login.',
		folder_create_example: example,
		do_not_retry: true,
		forbid_variants: ['web_url', 'disk_section', 'folder_path без parent', 'повторный login'],
		agent_message:
			'Создание папки: один login, затем folder create с auth_token и parent_directory_id из create_target. Не перебирайте варианты.'
	};
}

/**
 * @param {SkillKeyValueStorage | null} skillStorage
 * @param {number} parentId
 * @param {string} parentName
 */
function persistCreateTarget(skillStorage, parentId, parentName) {
	if (!skillStorage) return;
	skillStorage.set('r7_disk_my_documents_directory_id', String(parentId));
	skillStorage.set(
		'r7_disk_create_target',
		JSON.stringify({
			parent_directory_id: parentId,
			parent_name: parentName,
			disk_section: 'docs',
			can_create_here: true
		})
	);
}

const QUICK_ROOT_PROBE_IDS = [61, 1, 5, 9, 62, 63, 64, 65, 66, 67, 42, 50, 2, 3, 4];

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @returns {Promise<{ id: number, name: string } | null>}
 */
async function discoverPersonalRootQuick(baseUrl, authToken) {
	for (const candidateId of QUICK_ROOT_PROBE_IDS) {
		const fetched = await fetchDirectoryEntry(baseUrl, authToken, candidateId);
		if (!fetched.entry) continue;
		const entry = fetched.entry;
		const name = typeof entry.Name === 'string' ? entry.Name.trim() : '';
		const entryId = typeof entry.Id === 'number' ? entry.Id : candidateId;
		if (/мои\s*документ|my\s*documents/i.test(name)) {
			return { id: entryId, name: name || 'Мои документы' };
		}
	}
	return null;
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {number} directoryId
 * @returns {Promise<{ entry: Record<string, unknown> | null, status: number | null }>}
 */
async function fetchDirectoryEntry(baseUrl, authToken, directoryId) {
	const url = `${baseUrl}/api/v1/DocumentDirectory/Get?id=${encodeURIComponent(String(directoryId))}`;
	let response;
	try {
		response = await fetch(url, {
			method: 'GET',
			headers: { 'Content-Type': 'application/json', Authorization: authToken }
		});
	} catch {
		return { entry: null, status: null };
	}
	const status = response.status;
	if (!response.ok) return { entry: null, status };
	const rawText = await readUtf8Text(response);
	try {
		const payload = rawText ? JSON.parse(rawText) : [];
		const entries = Array.isArray(payload) ? payload : [payload];
		const entry = entries.find((item) => item && typeof item === 'object');
		return {
			entry:
				entry && typeof entry === 'object'
					? /** @type {Record<string, unknown>} */ (entry)
					: null,
			status
		};
	} catch {
		return { entry: null, status };
	}
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {Record<string, unknown>} params
 */
async function actionMove(baseUrl, authToken, params) {
	const folderId = resolvePositiveId(params?.folder_id);
	const toDirectoryId = resolvePositiveId(params?.to_directory_id);
	if (folderId == null || toDirectoryId == null) {
		return { ok: false, error: 'Для move нужны folder_id и to_directory_id (> 0).' };
	}

	const url =
		`${baseUrl}/api/v1/DocumentDirectory/Move?` +
		`Id=${encodeURIComponent(String(folderId))}&` +
		`toDirectoryId=${encodeURIComponent(String(toDirectoryId))}`;

	const http = await apiRequest('GET', url, authToken);
	if (!http.ok) return { ok: false, error: http.error, api_base_url: baseUrl };

	return {
		ok: true,
		action: 'move',
		folder_id: folderId,
		to_directory_id: toDirectoryId,
		data: toApiRecord(http.data),
		api_base_url: baseUrl
	};
}

