	const http = await apiRequest('POST', url, authToken, {
		Ids: ids,
		ToDirectoryId: toDirectoryId
	});
	if (!http.ok) return { ok: false, error: http.error, api_base_url: baseUrl };

	return {
		ok: true,
		action: 'conflict',
