			'После правки файла — force_redownload: true. Для текста — read_content.';
	return {
		ok: true,
		action: 'download',
		document_id: documentId,
		file_id: fileId,
		file_name: fileName,
		...(directoryId != null ? { directory_id: directoryId } : {}),
		do_not_retry: true,
		agent_stop: true,
		show_download_widget: false,
		widget_disabled: true,
		widget_render_once: false,
