/**
 * @param {Record<string, unknown>} state
 * @param {string} vfsPath
 * @param {string} text
 * @returns {Promise<{ ok: boolean, path?: string, error?: string }>}
 */
async function trySaveTextToVfs(state, vfsPath, text) {
	const caps = state.capabilities;
	if (!caps || typeof caps !== 'object') {
		return { ok: false, error: 'VFS недоступен: не объявлена capability vfs для инструмента.' };
	}
	const raw = /** @type {Record<string, unknown>} */ (caps).vfs;
	if (!raw || typeof raw !== 'object') {
		return { ok: false, error: 'VFS недоступен в runtime.' };
	}
	const vfs = /** @type {{ write?: (p: string, c: string) => Promise<unknown>, writeFile?: (p: string, c: string) => Promise<unknown> }} */ (
		raw
	);
	try {
		if (typeof vfs.write === 'function') {
			await vfs.write(vfsPath, text);
		} else if (typeof vfs.writeFile === 'function') {
			await vfs.writeFile(vfsPath, text);
		} else {
			return { ok: false, error: 'VFS: нет метода write/writeFile.' };
		}
		return { ok: true, path: vfsPath };
	} catch (err) {
		return { ok: false, error: errorMessage(err) };
	}
}

/**
 * @param {Uint8Array} bytes
 * @param {string} contentType
 * @returns {boolean}
 */
function isDocxBytes(bytes, contentType) {
	const base = contentType.split(';')[0].trim().toLowerCase();
	if (
		base.includes('wordprocessingml') ||
		base === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
	) {
		return true;
	}
	return bytes.length >= 2 && bytes[0] === 0x50 && bytes[1] === 0x4b;
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {Record<string, unknown>} params
 */
async function actionVersions(baseUrl, authToken, params) {
	const documentId = resolvePositiveId(params.document_id);
	if (documentId == null) {
		return { ok: false, error: 'Для versions нужен document_id (> 0).' };
	}

	const url = `${baseUrl}/api/v1/Documents/Versions?id=${encodeURIComponent(String(documentId))}`;
	const http = await apiRequest('GET', url, authToken);
	if (!http.ok) return { ok: false, error: http.error, api_base_url: baseUrl };

	const versions = normalizeVersionList(http.data);
	return buildWriteToolResponse({
		ok: true,
		action: 'versions',
		document_id: documentId,
		versions,
		version_count: versions.length,
		data: toApiRecord(http.data),
		api_base_url: baseUrl,
		agent_message:
			`Версий файла (id=${documentId}): ${versions.length}. ` +
			'Это не скачивание. Для «скачай файл» — один download с directory_id и name, без versions.'
	});
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {Record<string, unknown>} params
 */
async function actionChangeVersion(baseUrl, authToken, params) {
	const documentId = resolvePositiveId(params.document_id);
	const fileId = resolvePositiveId(params.file_id);
	if (documentId == null || fileId == null) {
		return { ok: false, error: 'Для change_version нужны document_id и file_id (> 0).' };
	}

	const url =
		`${baseUrl}/api/v1/Documents/ChangeVersion?` +
		`id=${encodeURIComponent(String(documentId))}&` +
		`fileId=${encodeURIComponent(String(fileId))}`;

	const http = await apiRequest('GET', url, authToken);
	if (!http.ok) return { ok: false, error: http.error, api_base_url: baseUrl };

	return {
		ok: true,
		action: 'change_version',
		document_id: documentId,
		file_id: fileId,
		data: toApiRecord(http.data),
		api_base_url: baseUrl
	};
}

/**
 * @param {string} baseUrl
 * @param {string} authToken
 * @param {Record<string, unknown>} params
 */
async function actionConvert(baseUrl, authToken, params) {
	const documentId = resolvePositiveId(params.document_id);
	const convertType = pickString(params.convert_type, params.type);
	if (documentId == null || !convertType) {
		return {
			ok: false,
			error: 'Для convert нужны document_id и convert_type (или type), например "pdf".'
		};
	}

	const url =
		`${baseUrl}/api/v1/Documents/Convert?` +
		`id=${encodeURIComponent(String(documentId))}&` +
		`type=${encodeURIComponent(convertType)}`;

	const http = await apiRequest('GET', url, authToken);
	if (!http.ok) return { ok: false, error: http.error, api_base_url: baseUrl };

	return {
		ok: true,
		action: 'convert',
		document_id: documentId,
		convert_type: convertType,
		data: toApiRecord(http.data),
		api_base_url: baseUrl
	};
}

/**
 * @param {string} method
 * @param {string} url
 * @param {string} authToken
 * @param {Record<string, unknown> | null} [body]
 */
async function apiRequest(method, url, authToken, body = null) {
	/** @type {RequestInit} */
	const init = {
		method,
		headers: {
			'Content-Type': 'application/json; charset=utf-8',
			Accept: 'application/json; charset=utf-8',
			Authorization: authToken
		}
	};
	if (body != null) {
		init.body = JSON.stringify(body);
	}

	let response;
	try {
		response = await fetch(url, init);
	} catch (err) {
		return { ok: false, error: `Сетевая ошибка ${method} ${url}: ${errorMessage(err)}` };
	}

	const rawText = await readUtf8Text(response);
	let payload = null;
	if (rawText) {
		try {
			payload = JSON.parse(rawText);
		} catch {
			if (!response.ok) {
				return {
					ok: false,
					status: response.status,
					error: `HTTP ${response.status}: ${truncate(rawText, 300)}`
				};
			}
			payload = rawText;
		}
	}

	if (!response.ok) {
		return {
			ok: false,
			status: response.status,
			error: `HTTP ${response.status}: ${truncate(rawText, 400)}`
		};
	}

	return { ok: true, status: response.status, data: unwrapApiData(payload) };
}

/**
 * @param {unknown} payload
 * @returns {unknown}
 */
function unwrapApiData(payload) {
	if (payload && typeof payload === 'object' && 'Response' in payload) {
		const response = /** @type {{ Response?: { Data?: unknown } }} */ (payload).Response;
		if (response && typeof response === 'object' && 'Data' in response) {
			return response.Data ?? payload;
		}
	}
	return payload;
}

/**
 * @param {unknown} value
 * @returns {Record<string, unknown>}
 */
function toApiRecord(value) {
	if (value && typeof value === 'object' && !Array.isArray(value)) {
		return /** @type {Record<string, unknown>} */ (value);
	}
	if (value == null) return {};
	return { result: value };
}

/**
 * @param {unknown} payload
 * @returns {number | null}
 */
function extractDocumentId(payload) {
	if (typeof payload === 'number' && Number.isFinite(payload)) return Math.trunc(payload);
	const data = unwrapApiData(payload);
	if (typeof data === 'number' && Number.isFinite(data)) return Math.trunc(data);
	if (data && typeof data === 'object') {
		const obj = /** @type {Record<string, unknown>} */ (data);
		if (typeof obj.Id === 'number') return obj.Id;
		if (typeof obj.id === 'number') return obj.id;
		if (typeof obj.DocumentId === 'number') return obj.DocumentId;
	}
	return null;
}

/**
 * @param {unknown} value
 * @returns {boolean | null}
 */
function coerceBoolean(value) {
	if (typeof value === 'boolean') return value;
	const data = unwrapApiData(value);
	if (typeof data === 'boolean') return data;
	if (data && typeof data === 'object') {
		const obj = /** @type {Record<string, unknown>} */ (data);
		if (typeof obj.Exists === 'boolean') return obj.Exists;
		if (typeof obj.exists === 'boolean') return obj.exists;
	}
	if (typeof data === 'string') {
		if (data.toLowerCase() === 'true') return true;
		if (data.toLowerCase() === 'false') return false;
	}
	return null;
}

/**
 * @param {unknown} data
 * @returns {Array<Record<string, unknown>>}
 */
function normalizeVersionList(data) {
	const unwrapped = unwrapApiData(data);
	/** @type {unknown[]} */
	let list = [];
	if (Array.isArray(unwrapped)) {
		list = unwrapped;
	} else if (unwrapped && typeof unwrapped === 'object') {
		const obj = /** @type {Record<string, unknown>} */ (unwrapped);
		if (Array.isArray(obj.Versions)) list = obj.Versions;
		else if (Array.isArray(obj.versions)) list = obj.versions;
	}
	return list
		.filter((item) => item && typeof item === 'object')
		.map((item) => {
			const row = /** @type {Record<string, unknown>} */ (item);
			return {
				FileId: row.FileId ?? row.fileId,
				Version: row.Version ?? row.version,
				Date: row.Date ?? row.date,
				Size: row.Size ?? row.size,
				Author: row.Author ?? row.author
			};
		});
}

/**
 * @param {unknown} primary
 * @param {unknown} [secondary]
 * @returns {number[]}
 */
function resolveIdList(primary, secondary) {
	const fromPrimary = normalizeIdArray(primary);
	if (fromPrimary.length > 0) return fromPrimary;
	const single = resolvePositiveId(secondary);
	return single != null ? [single] : [];
}

/**
 * @param {unknown} value
 * @returns {number[]}
 */
function normalizeIdArray(value) {
	if (typeof value === 'number' && Number.isFinite(value) && value > 0) {
		return [Math.trunc(value)];
	}
	if (typeof value === 'string' && value.trim()) {
		const parsed = Number(value.trim());
		if (Number.isFinite(parsed) && parsed > 0) return [Math.trunc(parsed)];
	}
	if (!Array.isArray(value)) return [];
	/** @type {number[]} */
	const ids = [];
	for (const item of value) {
		const id = resolvePositiveId(item);
		if (id != null) ids.push(id);
	}
	return ids;
}

/**
 * @param {unknown} value
 * @returns {number | null}
 */
function resolvePositiveId(value) {
	if (typeof value === 'number' && Number.isFinite(value) && value > 0) {
		return Math.trunc(value);
	}
	if (typeof value === 'string' && value.trim()) {
		const parsed = Number(value.trim());
		if (Number.isFinite(parsed) && parsed > 0) return Math.trunc(parsed);
	}
	return null;
}

/**
 * @param {unknown} value
 * @returns {string}
 */
function normalizeBase64Param(value) {
	if (typeof value !== 'string' || !value.trim()) return '';
	const trimmed = value.trim();
	const comma = trimmed.indexOf(',');
	if (trimmed.startsWith('data:') && comma >= 0) {
		return trimmed.slice(comma + 1).trim();
	}
	return trimmed;
}

/**
 * @param {string} base64
 * @returns {Uint8Array}
 */
function decodeBase64(base64) {
	const binary = atob(base64);
	const bytes = new Uint8Array(binary.length);
	for (let i = 0; i < binary.length; i++) {
		bytes[i] = binary.charCodeAt(i);
	}
	return bytes;
}

/**
 * @param {Uint8Array} bytes
 * @returns {string}
 */
function encodeBase64(bytes) {
	let binary = '';
	for (let i = 0; i < bytes.length; i++) {
		binary += String.fromCharCode(bytes[i]);
	}
	return btoa(binary);
}

/**
 * @param {Uint8Array[]} parts
 * @returns {Uint8Array}
 */
function concatBytes(parts) {
	let total = 0;
	for (const part of parts) total += part.length;
	const out = new Uint8Array(total);
	let offset = 0;
	for (const part of parts) {
		out.set(part, offset);
		offset += part.length;
	}
	return out;
}

/** @param {string} text @returns {Uint8Array} */
function encodeUtf8(text) {
	return new TextEncoder().encode(text);
}

/** @param {Uint8Array} bytes @returns {string} */
function decodeUtf8(bytes) {
	return new TextDecoder('utf-8').decode(bytes);
}

/**
 * @param {{ text: () => Promise<string> }} response
 * @returns {Promise<string>}
 */
async function readUtf8Text(response) {
	return response.text();
}

/**
 * @param {string} boundary
 * @param {string} fileName
 * @param {string} contentType
 * @param {Uint8Array} fileBytes
 * @returns {Uint8Array}
 */
/**
 * @param {Uint8Array} bytes
 * @returns {string | Blob}
 */
function toFetchBinaryBody(bytes) {
	if (typeof Blob === 'function') {
		return new Blob([bytes]);
	}
	return uint8ToBinaryString(bytes);
}

/**
 * @param {Uint8Array} bytes
 * @returns {string}
 */
function uint8ToBinaryString(bytes) {
	let s = '';
	for (let i = 0; i < bytes.length; i++) s += String.fromCharCode(bytes[i]);
	return s;
}

function buildMultipartUploadBody(boundary, fileName, contentType, fileBytes) {
	const asciiFallback = toAsciiFallbackFilename(fileName);
	const utf8FileName = encodeURIComponent(fileName).replace(/[!'()*]/g, (c) =>
		`%${c.charCodeAt(0).toString(16).toUpperCase()}`
	);
	const preamble =
		`--${boundary}\r\n` +
		`Content-Disposition: form-data; name="file"; filename="${asciiFallback}"; filename*=UTF-8''${utf8FileName}\r\n` +
		`Content-Type: ${contentType}\r\n\r\n`;
	const epilogue = `\r\n--${boundary}--\r\n`;
	return concatBytes([encodeUtf8(preamble), fileBytes, encodeUtf8(epilogue)]);
}

/**
 * @param {string} fileName
 * @returns {string}
 */
function toAsciiFallbackFilename(fileName) {
	const dot = fileName.lastIndexOf('.');
	const ext = dot > 0 ? fileName.slice(dot) : '';
	const base = (dot > 0 ? fileName.slice(0, dot) : fileName).replace(/[^\x20-\x7E]/g, '_');
	const safeBase = (base.replace(/_+/g, '_').replace(/^_|_$/g, '') || 'file').slice(0, 80);
	const safeExt = ext.replace(/[^\x20-\x7E.]/g, '');
	return safeBase + safeExt;
}

/**
 * @param {string} fileName
 * @param {string} explicit
 * @returns {string}
 */
function inferMimeType(fileName, explicit) {
	if (explicit) {
		if (explicit.startsWith('text/') && !explicit.includes('charset=')) {
			return `${explicit}; charset=utf-8`;
		}
		return explicit;
	}
	const lower = fileName.toLowerCase();
	if (lower.endsWith('.txt') || lower.endsWith('.md') || lower.endsWith('.csv')) {
		return 'text/plain; charset=utf-8';
	}
	if (lower.endsWith('.json')) return 'application/json; charset=utf-8';
	if (lower.endsWith('.xml')) return 'application/xml; charset=utf-8';
	if (lower.endsWith('.html') || lower.endsWith('.htm')) return 'text/html; charset=utf-8';
	if (lower.endsWith('.docx')) {
		return 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
	}
	if (lower.endsWith('.doc')) return 'application/msword';
	if (lower.endsWith('.xlsx')) {
		return 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
	}
	if (lower.endsWith('.pdf')) return 'application/pdf';
	return 'application/octet-stream';
}

/**
 * @param {string} text
 * @returns {string}
 */
function escapeXmlText(text) {
	return text
		.replace(/&/g, '&amp;')
		.replace(/</g, '&lt;')
		.replace(/>/g, '&gt;')
		.replace(/"/g, '&quot;')
		.replace(/'/g, '&apos;');
}

/**
 * @typedef {{ text: string, bold: boolean, italic: boolean, fontSizePt?: number }} InlineRun
 */

/**
 * @param {string} source
 * @param {number} startIndex
 * @returns {{ fontSizePt?: number, nextIndex: number }}
 */
function parseOptionalFontSizePrefix(source, startIndex) {
	if (source[startIndex] !== '{') return { nextIndex: startIndex };
	const close = source.indexOf('}', startIndex);
	if (close < 0) return { nextIndex: startIndex };
	const num = Number(source.slice(startIndex + 1, close));
	if (!Number.isFinite(num) || num <= 0 || num > 163) return { nextIndex: startIndex };
	return { fontSizePt: Math.round(num), nextIndex: close + 1 };
}

/**
 * Разметка в content_text для DOCX: **жирный**, *курсив*, **{26}текст** — жирный 26 pt.
 * @param {string} source
 * @returns {InlineRun[]}
 */
function parseInlineMarkup(source) {
	/** @type {InlineRun[]} */
	const runs = [];
	let i = 0;
	let buffer = '';

	const flush = (bold, italic, fontSizePt) => {
		if (!buffer) return;
		runs.push({
			text: buffer,
			bold,
			italic,
			...(fontSizePt != null ? { fontSizePt } : {})
		});
		buffer = '';
	};

	while (i < source.length) {
		if (source.startsWith('**', i)) {
			flush(false, false, undefined);
			i += 2;
			const sizeParsed = parseOptionalFontSizePrefix(source, i);
			i = sizeParsed.nextIndex;
			const end = source.indexOf('**', i);
			if (end === -1) {
				buffer += '**';
				break;
			}
			runs.push({
				text: source.slice(i, end),
				bold: true,
				italic: false,
				...(sizeParsed.fontSizePt != null ? { fontSizePt: sizeParsed.fontSizePt } : {})
			});
			i = end + 2;
			continue;
		}
		if (source[i] === '*') {
			flush(false, false, undefined);
			i += 1;
			const end = source.indexOf('*', i);
			if (end === -1) {
				buffer += '*';
				break;
			}
			runs.push({ text: source.slice(i, end), bold: false, italic: true });
			i = end + 1;
			continue;
		}
		buffer += source[i];
		i += 1;
	}
	flush(false, false, undefined);
	if (runs.length === 0) runs.push({ text: '', bold: false, italic: false });
	return runs;
}

/**
 * @param {string} line
 * @returns {string}
 */
function buildDocxParagraphXml(line) {
	if (!line) {
		return '<w:p><w:r><w:t xml:space="preserve"></w:t></w:r></w:p>';
	}
	const runs = parseInlineMarkup(line);
	const inner = runs.map((run) => buildDocxRunXml(run)).join('');
	return `<w:p>${inner}</w:p>`;
}

/**
 * @param {InlineRun} run
 * @returns {string}
 */
function buildDocxRunXml(run) {
	const props = [];
	if (run.bold) props.push('<w:b/>');
	if (run.italic) props.push('<w:i/>');
	if (run.fontSizePt != null && run.fontSizePt > 0) {
		const halfPoints = Math.round(run.fontSizePt * 2);
		props.push(`<w:sz w:val="${halfPoints}"/>`);
		props.push(`<w:szCs w:val="${halfPoints}"/>`);
	}
	const rPr = props.length > 0 ? `<w:rPr>${props.join('')}</w:rPr>` : '';
	const text = escapeXmlText(run.text);
	return `<w:r>${rPr}<w:t xml:space="preserve">${text}</w:t></w:r>`;
}

/**
 * URI схемы OOXML. Литерал http в исходнике Ladcraft добавляет в network.hosts (ложный внешний хост).
 * @param {string} path
 * @returns {string}
 */
function pkgSchemaUri(path) {
	const scheme = [0x68, 0x74, 0x74, 0x70, 0x3a, 0x2f, 0x2f]
		.map((code) => String.fromCharCode(code))
		.join('');
	return scheme + 'schemas.openxmlformats.org' + path;
}

/**
 * Минимальный DOCX (ZIP) с одним абзацем текста — без python-docx/pip и без сетевых запросов.
 * @param {string} paragraphText
 * @returns {Uint8Array}
 */
function buildMinimalDocxBytes(paragraphText) {
	const nsWord = pkgSchemaUri('/wordprocessingml/2006/main');
	const nsContentTypes = pkgSchemaUri('/package/2006/content-types');
	const nsRels = pkgSchemaUri('/package/2006/relationships');
	const relOfficeDoc = pkgSchemaUri('/officeDocument/2006/relationships/officeDocument');

	const paragraphs = String(paragraphText).split(/\r?\n/);
	const bodyXml = paragraphs.map((line) => buildDocxParagraphXml(line)).join('');

	const documentXml = encodeUtf8(
		'<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
			`<w:document xmlns:w="${nsWord}">` +
			`<w:body>${bodyXml}</w:body></w:document>`
	);
	const contentTypes = encodeUtf8(
		'<?xml version="1.0" encoding="UTF-8"?>' +
			`<Types xmlns="${nsContentTypes}">` +
			'<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>' +
			'<Default Extension="xml" ContentType="application/xml"/>' +
			'<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>' +
			'<Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/>' +
			'<Override PartName="/docProps/core.xml" ContentType="application/vnd.openxmlformats-officedocument.extended-properties+xml"/>' +
			'</Types>'
	);
	const stylesXml = encodeUtf8(
		'<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
			`<w:styles xmlns:w="${nsWord}">` +
			'<w:docDefaults><w:rPrDefault><w:rPr><w:sz w:val="22"/><w:szCs w:val="22"/></w:rPr></w:rPrDefault></w:docDefaults>' +
			'<w:style w:type="paragraph" w:default="1" w:styleId="Normal">' +
			'<w:name w:val="Normal"/><w:qFormat/>' +
			'<w:pPr><w:spacing w:after="160"/></w:pPr>' +
			'</w:style></w:styles>'
	);
	const nsCore = pkgSchemaUri('/package/2006/metadata/core-properties');
	const nsDc = 'http://purl.org/dc/elements/1.1/';
	const coreXml = encodeUtf8(
		'<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
			`<cp:coreProperties xmlns:cp="${nsCore}" xmlns:dc="${nsDc}">` +
			'<dc:creator>Ladcraft r7-disk-api</dc:creator>' +
			'</cp:coreProperties>'
	);
	const packageRels = encodeUtf8(
		'<?xml version="1.0" encoding="UTF-8"?>' +
			`<Relationships xmlns="${nsRels}">` +
			`<Relationship Id="rId1" Type="${relOfficeDoc}" Target="word/document.xml"/>` +
			'</Relationships>'
	);
	const documentRels = encodeUtf8(
		'<?xml version="1.0" encoding="UTF-8"?>' +
			`<Relationships xmlns="${nsRels}"></Relationships>`
	);

	return createZipArchive([
		{ path: '[Content_Types].xml', data: contentTypes },
		{ path: '_rels/.rels', data: packageRels },
		{ path: 'docProps/core.xml', data: coreXml },
		{ path: 'word/document.xml', data: documentXml },
		{ path: 'word/styles.xml', data: stylesXml },
		{ path: 'word/_rels/document.xml.rels', data: documentRels }
	]);
}

/**
 * @param {Array<{ path: string, data: Uint8Array }>} entries
 * @returns {Uint8Array}
 */
function createZipArchive(entries) {
	/** @type {Uint8Array[]} */
	const parts = [];
	/** @type {Array<{ path: string, data: Uint8Array, offset: number, crc: number }>} */
	const central = [];
	let offset = 0;

	for (const entry of entries) {
		const nameBytes = encodeUtf8(entry.path.replace(/\\/g, '/'));
		const crc = crc32(entry.data);
		const local = buildZipLocalHeader(nameBytes, entry.data, crc);
		parts.push(local);
		central.push({ path: entry.path, data: entry.data, offset, crc });
		offset += local.length;
	}

	const centralStart = offset;
	let centralSize = 0;
	for (const entry of central) {
		const nameBytes = encodeUtf8(entry.path.replace(/\\/g, '/'));
		const centralHeader = buildZipCentralHeader(nameBytes, entry.data, entry.offset, entry.crc);
		parts.push(centralHeader);
		centralSize += centralHeader.length;
	}

	parts.push(buildZipEndRecord(central.length, centralSize, centralStart));
	return concatBytes(parts);
}

/**
 * @param {Uint8Array} nameBytes
 * @param {Uint8Array} data
 * @param {number} crc
 * @returns {Uint8Array}
 */
function buildZipLocalHeader(nameBytes, data, crc) {
	const header = new Uint8Array(30 + nameBytes.length);
	const view = new DataView(header.buffer);
	view.setUint32(0, 0x04034b50, true);
	view.setUint16(4, 20, true);
	view.setUint16(6, 0, true);
	view.setUint16(8, 0, true);
	view.setUint16(10, 0, true);
	view.setUint16(12, 0, true);
	view.setUint32(14, crc, true);
	view.setUint32(18, data.length, true);
	view.setUint32(22, data.length, true);
	view.setUint16(26, nameBytes.length, true);
	view.setUint16(28, 0, true);
	header.set(nameBytes, 30);
	return concatBytes([header, data]);
}

/**
 * @param {Uint8Array} nameBytes
 * @param {Uint8Array} data
 * @param {number} offset
 * @param {number} crc
 * @returns {Uint8Array}
 */
function buildZipCentralHeader(nameBytes, data, offset, crc) {
	const header = new Uint8Array(46 + nameBytes.length);
	const view = new DataView(header.buffer);
	view.setUint32(0, 0x02014b50, true);
	view.setUint16(4, 20, true);
	view.setUint16(6, 20, true);
	view.setUint16(8, 0, true);
	view.setUint16(10, 0, true);
	view.setUint16(12, 0, true);
	view.setUint16(14, 0, true);
	view.setUint32(16, crc, true);
	view.setUint32(20, data.length, true);
	view.setUint32(24, data.length, true);
	view.setUint16(28, nameBytes.length, true);
	view.setUint16(30, 0, true);
	view.setUint16(32, 0, true);
	view.setUint16(34, 0, true);
	view.setUint16(36, 0, true);
	view.setUint32(38, 0, true);
	view.setUint32(42, offset, true);
	header.set(nameBytes, 46);
	return header;
}

/**
 * @param {number} entryCount
 * @param {number} centralSize
 * @param {number} centralOffset
 * @returns {Uint8Array}
 */
function buildZipEndRecord(entryCount, centralSize, centralOffset) {
	const footer = new Uint8Array(22);
	const view = new DataView(footer.buffer);
	view.setUint32(0, 0x06054b50, true);
	view.setUint16(4, 0, true);
	view.setUint16(6, 0, true);
	view.setUint16(8, entryCount, true);
	view.setUint16(10, entryCount, true);
	view.setUint32(12, centralSize, true);
	view.setUint32(16, centralOffset, true);
	view.setUint16(20, 0, true);
	return footer;
}

/** @type {Uint32Array} */
let crc32TableCache = null;

/**
 * @returns {Uint32Array}
 */
function getCrc32Table() {
	if (crc32TableCache) return crc32TableCache;
	crc32TableCache = new Uint32Array(256);
	for (let i = 0; i < 256; i++) {
		let c = i;
		for (let k = 0; k < 8; k++) {
			c = c & 1 ? 0xedb88320 ^ (c >>> 1) : c >>> 1;
		}
		crc32TableCache[i] = c >>> 0;
	}
	return crc32TableCache;
}

/**
 * @param {Uint8Array} bytes
 * @returns {number}
 */
function crc32(bytes) {
	const table = getCrc32Table();
	let crc = 0xffffffff;
	for (let i = 0; i < bytes.length; i++) {
		crc = table[(crc ^ bytes[i]) & 0xff] ^ (crc >>> 8);
	}
	return (crc ^ 0xffffffff) >>> 0;
}

/**
 * @param {string} contentType
 * @returns {boolean}
 */
function isTextContentType(contentType) {
	const base = contentType.split(';')[0].trim().toLowerCase();
	return base.startsWith('text/') || base === 'application/json' || base === 'application/xml';
}

/**
 * @param {string} baseUrl
 * @param {string} login
 * @param {string} password
 * @param {SkillKeyValueStorage | null} skillStorage
 * @param {unknown} authTokenParam
 */
async function ensureAuthToken(baseUrl, login, password, skillStorage, authTokenParam) {
	let authToken = typeof authTokenParam === 'string' ? authTokenParam.trim() : '';
	let authFromCache = false;
	if (!authToken && skillStorage) {
		const cached = skillStorage.get('r7_disk_auth_token');
		if (typeof cached === 'string' && cached.trim()) {
			authToken = cached.trim();
			authFromCache = true;
		}
	} else if (authToken) {
		authFromCache = true;
	}
	if (authToken) {
		return { ok: true, auth_token: authToken, auth_from_cache: authFromCache };
	}
	const loginResult = await loginInline(baseUrl, login, password, skillStorage);
	if (!loginResult.ok) return { ok: false, error: loginResult.error };
	return { ok: true, auth_token: loginResult.auth_token, auth_from_cache: false };
}

/**
 * @param {Record<string, unknown> & { ok: boolean }} result
 * @param {boolean} authFromCache
 * @returns {Record<string, unknown> & { ok: boolean, auth_from_cache: boolean, forbid_followup_tools: string[], session_note?: string }}
 */
function withSessionAuthHints(result, authFromCache) {
	const record = /** @type {Record<string, unknown>} */ (/** @type {unknown} */ (result));
	const existing = Array.isArray(record.forbid_followup_tools)
		? /** @type {string[]} */ (record.forbid_followup_tools)
		: [];
	const merged = [...new Set([...existing, 'r7_disk_login'])];
	return {
		...result,
		auth_from_cache: authFromCache,
		...(authFromCache
			? {
					session_note:
						'Токен из skillStorage. **Не** вызывайте r7_disk_login повторно в этой сессии.',
					forbid_followup_tools: merged
				}
			: { forbid_followup_tools: merged })
	};
}

/**
 * @param {string} baseUrl
 * @param {string} login
 * @param {string} password
 * @param {SkillKeyValueStorage | null} skillStorage
 */
async function loginInline(baseUrl, login, password, skillStorage) {
	if (!login || !password) {
		return {
			ok: false,
			error: 'Нет auth_token и не заданы R7_DISK_LOGIN/R7_DISK_PASSWORD для авто-login.'
		};
	}
	const url = `${baseUrl}/api/v2/auth/Login`;
	const response = await fetch(url, {
		method: 'POST',
		headers: { 'Content-Type': 'application/json; charset=utf-8' },
		body: JSON.stringify({ Login: login, Password: password })
	});
	const rawText = await readUtf8Text(response);
	let payload;
	try {
		payload = rawText ? JSON.parse(rawText) : {};
	} catch {
		return { ok: false, error: `Login: ответ не JSON (HTTP ${response.status}).` };
	}
	if (!response.ok) {
		return { ok: false, error: `Login HTTP ${response.status}: ${truncate(rawText, 300)}` };
	}
	const authToken = payload?.Response?.Data?.Tokens?.AuthToken;
	if (typeof authToken !== 'string' || !authToken) {
		return { ok: false, error: 'Login: AuthToken не найден.' };
	}
	if (skillStorage) {
		skillStorage.set('r7_disk_auth_token', authToken);
		skillStorage.set('r7_disk_base_url', baseUrl);
	}
	return { ok: true, auth_token: authToken };
}

/**
 * @param {Record<string, unknown>} state
 * @returns {Record<string, unknown>}
 */
function readUserEnv(state) {
	const env = state.environment;
	if (!env || typeof env !== 'object') return {};
	const user = /** @type {Record<string, unknown>} */ (env).user;
	if (!user || typeof user !== 'object') return {};
	return /** @type {Record<string, unknown>} */ (user);
}

/**
 * @param {Record<string, unknown>} state
 * @param {Record<string, unknown>} params
 * @param {SkillKeyValueStorage | null} skillStorage
 * @returns {string}
 */
function resolveBaseUrl(state, params, skillStorage) {
	const userEnv = readUserEnv(state);
	const fromParam = typeof params.base_url === 'string' ? params.base_url.trim() : '';
	if (fromParam) return fromParam.replace(/\/+$/, '');
	if (skillStorage) {
		const cached = skillStorage.get('r7_disk_base_url');
		if (typeof cached === 'string' && cached.trim()) {
			return cached.trim().replace(/\/+$/, '');
		}
	}
	return pickString('', userEnv.R7_DISK_BASE_URL).replace(/\/+$/, '');
}

/**
 * @param {unknown} primary
 * @param {unknown} fallback
 * @returns {string}
 */
function pickString(primary, fallback) {
	if (typeof primary === 'string' && primary.trim()) return primary.trim();
	if (typeof fallback === 'string' && fallback.trim()) return fallback.trim();
	return '';
}

/**
 * @typedef {Object} SkillKeyValueStorage
 * @property {(key: string) => unknown} get
 * @property {(key: string, value: string) => void} set
 * @property {(key: string) => void} [delete]
 */

/**
 * @param {SkillKeyValueStorage | null | undefined} skillStorage
 * @param {string} key
 */
function kvRemove(skillStorage, key) {
	if (!skillStorage) return;
	if (typeof skillStorage.delete === 'function') {
		skillStorage.delete(key);
		return;
	}
	skillStorage.set(key, '');
}

/**
 * @param {Record<string, unknown>} state
 * @returns {SkillKeyValueStorage | null}
 */
function resolveSkillStorage(state) {
	const caps = state.capabilities;
	if (!caps || typeof caps !== 'object') return null;
	const record = /** @type {Record<string, unknown>} */ (caps);
	const raw = record.skillStorage ?? record.storage ?? record['key-value-storage'];
	if (!raw || typeof raw !== 'object') return null;
	const kv = /** @type {{ get?: unknown; set?: unknown; delete?: unknown }} */ (raw);
	if (typeof kv.get !== 'function' || typeof kv.set !== 'function') return null;
	return /** @type {SkillKeyValueStorage} */ (raw);
}

/**
 * @param {unknown} value
 * @returns {string}
 */
function errorMessage(value) {
	return value instanceof Error ? value.message : String(value);
}

/**
 * @param {string} text
 * @param {number} max
 * @returns {string}
 */
function truncate(text, max) {
	if (text.length <= max) return text;
	return `${text.slice(0, max)}…`;
}

/**
 * Подсказка агенту: не выдумывать данные вне полей ответа tool.
 * @template T
 * @param {T} fields
 * @param {string[]} citeOnlyFields
 * @returns {T}
 */
function withFactualCitation(fields, citeOnlyFields) {
	const record = /** @type {Record<string, unknown>} */ (/** @type {unknown} */ (fields));
	const msg = typeof record.agent_message === 'string' ? record.agent_message : '';
	const hint = ` Цитируй только ${citeOnlyFields.join(', ')} — не выдумывай.`;
	return /** @type {T} */ ({
		...fields,
		do_not_invent_content: true,
		cite_only_fields: citeOnlyFields,
		agent_message: msg.includes('не выдумывай') ? msg : msg + hint
	});
}

/* Shared GOST34 DOCX formatter (from gost34-tz-formatter). Do not edit by hand — sync from formatGost34TaskDescriptionDocx.js */
function validateTemplateBytes(bytes, templatePath) {
	if (!looksLikeZip(bytes)) {
		return {
			ok: false,
			error:
				'Шаблон прочитан не как оригинальный DOCX (нет ZIP). Ladcraft хранит DOCX как .md — нужен readFile(..., {source:"original"}). Путь: ' +
				templatePath,
		};
	}
	if (bytes.length < 50000) {
		return {
			ok: false,
			error:
				'Шаблон слишком мал (' +
				bytes.length +
				' байт) — это не полный DOCX с инженерной рамкой (~69 KB). Перезагрузите gost34_task_description_template.docx.',
		};
	}
	try {
		const entries = readZipEntries(bytes);
		const footers = entries.filter((entry) => /^word\/footer\d+\.xml$/.test(entry.name));
		const headers = entries.filter((entry) => /^word\/header\d+\.xml$/.test(entry.name));
		if (footers.length < 3 || headers.length < 3) {
			return {
				ok: false,
				error:
					'Шаблон без колонтитулов ГОСТ (footer=' +
					footers.length +
					', header=' +
					headers.length +
					'). Загрузите эталонный шаблон заново.',
			};
		}
	} catch (error) {
		return {
			ok: false,
			error: 'Шаблон повреждён: ' + String(error?.message || error),
		};
	}
	return { ok: true };
}

function looksLikeZip(bytes) {
	return bytes.length >= 4 && bytes[0] === 0x50 && bytes[1] === 0x4b;
}
function encodeUtf8(text) {
	if (typeof TextEncoder !== 'undefined') {
		return new TextEncoder().encode(text);
	}
	return Uint8Array.from(Buffer.from(text, 'utf-8'));
}

function decodeUtf8(bytes) {
	if (typeof TextDecoder !== 'undefined') {
		return new TextDecoder('utf-8').decode(bytes);
	}
	return Buffer.from(bytes).toString('utf-8');
}

function readU16(bytes, offset) {
	return bytes[offset] | (bytes[offset + 1] << 8);
}

function readU32(bytes, offset) {
	return (
		(bytes[offset] |
			(bytes[offset + 1] << 8) |
			(bytes[offset + 2] << 16) |
			(bytes[offset + 3] << 24)) >>>
		0
	);
}

function writeU16(target, offset, value) {
	target[offset] = value & 0xff;
	target[offset + 1] = (value >> 8) & 0xff;
}

function writeU32(target, offset, value) {
	target[offset] = value & 0xff;
	target[offset + 1] = (value >> 8) & 0xff;
	target[offset + 2] = (value >> 16) & 0xff;
	target[offset + 3] = (value >> 24) & 0xff;
}

function getZlib() {
	if (typeof zlib !== 'undefined' && zlib && typeof zlib.inflateRawSync === 'function') {
		return zlib;
	}
	const moduleIds = ['zlib', 'node:zlib'];
	for (let i = 0; i < moduleIds.length; i += 1) {
		try {
			const mod = require(moduleIds[i]);
			if (mod && typeof mod.inflateRawSync === 'function' && typeof mod.deflateRawSync === 'function') {
				return mod;
			}
		} catch (_) {
			// try next module id
		}
	}
	return null;
}

function inflateRaw(data) {
	const z = getZlib();
	if (!z) {
		throw new Error('zlib недоступен');
	}
	return Uint8Array.from(z.inflateRawSync(data));
}

function deflateRaw(data) {
	const z = getZlib();
	if (!z) {
		throw new Error('zlib недоступен');
	}
	return Uint8Array.from(z.deflateRawSync(data));
}

function readZipEntries(bytes) {
	const central = readCentralDirectory(bytes);
	const entries = [];
	for (const meta of central) {
		const localOffset = meta.localHeaderOffset;
		if (readU32(bytes, localOffset) !== 0x04034b50) {
			throw new Error(`Некорректный local header: ${meta.name}`);
		}
		const nameLen = readU16(bytes, localOffset + 26);
		const extraLen = readU16(bytes, localOffset + 28);
		const dataStart = localOffset + 30 + nameLen + extraLen;
		const compData = bytes.slice(dataStart, dataStart + meta.compressedSize);
		let data;
		if (meta.compression === 0) {
			data = compData;
		} else if (meta.compression === 8) {
			data = inflateRaw(compData);
		} else {
			throw new Error(`Неподдерживаемое сжатие ZIP: ${meta.compression}`);
		}
		entries.push({ name: meta.name, compression: meta.compression, data });
	}
	return entries;
}

function readCentralDirectory(bytes) {
	let eocdOffset = -1;
	for (let i = bytes.length - 22; i >= 0; i -= 1) {
		if (readU32(bytes, i) === 0x06054b50) {
			eocdOffset = i;
			break;
		}
	}
	if (eocdOffset < 0) {
		throw new Error('EOCD не найден в ZIP');
	}

	const totalEntries = readU16(bytes, eocdOffset + 10);
	const centralOffset = readU32(bytes, eocdOffset + 16);
	const entries = [];
	let offset = centralOffset;

	for (let i = 0; i < totalEntries; i += 1) {
		if (readU32(bytes, offset) !== 0x02014b50) {
			throw new Error('Некорректная central directory');
		}
		const compression = readU16(bytes, offset + 10);
		const crc = readU32(bytes, offset + 16);
		const compressedSize = readU32(bytes, offset + 20);
		const uncompressedSize = readU32(bytes, offset + 24);
		const nameLen = readU16(bytes, offset + 28);
		const extraLen = readU16(bytes, offset + 30);
		const commentLen = readU16(bytes, offset + 32);
		const localHeaderOffset = readU32(bytes, offset + 42);
		const name = decodeUtf8(bytes.slice(offset + 46, offset + 46 + nameLen));
		entries.push({
			name,
			compression,
			crc,
			compressedSize,
			uncompressedSize,
			localHeaderOffset,
		});
		offset += 46 + nameLen + extraLen + commentLen;
	}

	return entries;
}

const CRC_TABLE = (() => {
	const table = new Uint32Array(256);
	for (let i = 0; i < 256; i += 1) {
		let c = i;
		for (let j = 0; j < 8; j += 1) {
			c = c & 1 ? 0xedb88320 ^ (c >>> 1) : c >>> 1;
		}
		table[i] = c >>> 0;
	}
	return table;
})();

function crc32(bytes) {
	let crc = 0xffffffff;
	for (let i = 0; i < bytes.length; i += 1) {
		crc = (CRC_TABLE[(crc ^ bytes[i]) & 0xff] ^ (crc >>> 8)) >>> 0;
	}
	return (crc ^ 0xffffffff) >>> 0;
}

function readZipArchive(bytes) {
	const central = readCentralDirectory(bytes);
	return central.map((meta) => {
		const localOffset = meta.localHeaderOffset;
		if (readU32(bytes, localOffset) !== 0x04034b50) {
			throw new Error(`Некорректный local header: ${meta.name}`);
		}
		const nameLen = readU16(bytes, localOffset + 26);
		const extraLen = readU16(bytes, localOffset + 28);
		const dataStart = localOffset + 30 + nameLen + extraLen;
		const compressedData = bytes.slice(dataStart, dataStart + meta.compressedSize);
		let data;
		if (meta.compression === 0) {
			data = compressedData;
		} else if (meta.compression === 8) {
			data = inflateRaw(compressedData);
		} else {
			throw new Error(`Неподдерживаемое сжатие ZIP: ${meta.compression}`);
		}
		return {
			name: meta.name,
			compression: meta.compression,
			crc: meta.crc,
			compressedSize: meta.compressedSize,
			uncompressedSize: meta.uncompressedSize,
			compressedData,
			data,
			preserveRaw: true,
		};
	});
}

function createZipEntryFromData(name, data) {
	return { name, data, preserveRaw: false };
}

function writeZipEntries(entries) {
	const parts = [];
	const central = [];
	let offset = 0;

	for (const entry of entries) {
		const nameBytes = encodeUtf8(entry.name);
		let method = entry.compression || 0;
		let compressed;
		let uncompressed;
		let checksum = entry.crc || 0;

		if (entry.preserveRaw && entry.compressedData) {
			compressed = entry.compressedData;
			uncompressed = entry.data;
			method = entry.compression;
			if (!checksum) {
				checksum = crc32(uncompressed);
			}
		} else {
			uncompressed = entry.data;
			checksum = crc32(uncompressed);
			compressed = uncompressed;
			method = 0;
			try {
				const deflated = deflateRaw(uncompressed);
				if (deflated.length < uncompressed.length) {
					compressed = deflated;
					method = 8;
				}
			} catch (_) {
				compressed = uncompressed;
				method = 0;
			}
		}

		const local = new Uint8Array(30 + nameBytes.length + compressed.length);
		writeU32(local, 0, 0x04034b50);
		writeU16(local, 4, 20);
		writeU16(local, 6, 0);
		writeU16(local, 8, method);
		writeU16(local, 10, 0);
		writeU16(local, 12, 0);
		writeU32(local, 14, checksum);
		writeU32(local, 18, compressed.length);
		writeU32(local, 22, uncompressed.length);
		writeU16(local, 26, nameBytes.length);
		writeU16(local, 28, 0);
		local.set(nameBytes, 30);
		local.set(compressed, 30 + nameBytes.length);
		parts.push(local);
		central.push({
			nameBytes,
			method,
			checksum,
			compressedSize: compressed.length,
			uncompressedSize: uncompressed.length,
			offset,
		});
		offset += local.length;
	}

	let centralSize = 0;
	for (const entry of central) {
		const header = new Uint8Array(46 + entry.nameBytes.length);
		writeU32(header, 0, 0x02014b50);
		writeU16(header, 4, 20);
		writeU16(header, 6, 20);
		writeU16(header, 8, 0);
		writeU16(header, 10, entry.method);
		writeU16(header, 12, 0);
		writeU16(header, 14, 0);
		writeU32(header, 16, entry.checksum);
		writeU32(header, 20, entry.compressedSize);
		writeU32(header, 24, entry.uncompressedSize);
		writeU16(header, 28, entry.nameBytes.length);
		writeU16(header, 30, 0);
		writeU16(header, 32, 0);
		writeU16(header, 34, 0);
		writeU16(header, 36, 0);
		writeU32(header, 38, 0);
		writeU32(header, 42, entry.offset);
		header.set(entry.nameBytes, 46);
		parts.push(header);
		centralSize += header.length;
	}

	const end = new Uint8Array(22);
	writeU32(end, 0, 0x06054b50);
	writeU16(end, 4, 0);
	writeU16(end, 6, 0);
	writeU16(end, 8, central.length);
	writeU16(end, 10, central.length);
	writeU32(end, 12, centralSize);
	writeU32(end, 16, offset);
	writeU16(end, 20, 0);
	parts.push(end);

	const total = parts.reduce((sum, part) => sum + part.length, 0);
	const out = new Uint8Array(total);
	let cursor = 0;
	for (const part of parts) {
		out.set(part, cursor);
		cursor += part.length;
	}
	return out;
}

function writeZip(entries) {
	return writeZipEntries(
		entries.map((entry) => {
			if (entry.preserveRaw) {
				return entry;
			}
			return createZipEntryFromData(entry.name, entry.data);
		})
	);
}

function extractDocxPlainText(bytes) {
	const entries = readZipEntries(bytes);
	const document = entries.find((entry) => entry.name === 'word/document.xml');
	if (!document) {
		return '';
	}
	const xml = decodeUtf8(document.data);
	const chunks = [];
	const regex = /<w:t[^>]*>([\s\S]*?)<\/w:t>/g;
	let match = regex.exec(xml);
	while (match) {
		chunks.push(
			match[1]
				.replace(/&lt;/g, '<')
				.replace(/&gt;/g, '>')
				.replace(/&amp;/g, '&')
				.replace(/&quot;/g, '"')
				.replace(/&apos;/g, "'")
		);
		match = regex.exec(xml);
	}
	return chunks.join('\n');
}

function buildDocxFromTemplate(templateBytes, inputSectionMap, meta) {
	const archive = readZipArchive(templateBytes);
	const document = archive.find((entry) => entry.name === 'word/document.xml');
	if (!document) {
		throw new Error('word/document.xml не найден в шаблоне');
	}
	const templateXml = decodeUtf8(document.data);
	const merged = mergeTemplateDocument(templateXml, inputSectionMap, meta);
	const updated = archive.map((entry) => {
		if (entry.name === 'word/document.xml') {
			return createZipEntryFromData(entry.name, encodeUtf8(merged.xml));
		}
		if (/^word\/(header|footer)\d+\.xml$/.test(entry.name)) {
			const filled = fillTitlePlaceholders(decodeUtf8(entry.data), meta);
			return createZipEntryFromData(entry.name, encodeUtf8(filled));
		}
		return entry;
	});
	return {
		bytes: writeZipEntries(updated),
		fillStats: merged.fillStats,
		recommendations: merged.recommendations,
	};
}

function extractDocumentParagraphs(bytes) {
	const entries = readZipEntries(bytes);
	const document = entries.find((entry) => entry.name === 'word/document.xml');
	if (!document) {
		return [];
	}
	return parseDocumentParagraphs(decodeUtf8(document.data));
}

function parseDocumentParagraphs(xml) {
	const paragraphs = xml.match(/<w:p[\s\S]*?<\/w:p>/g) || [];
	return paragraphs.map((paragraphXml) => {
		const style = (paragraphXml.match(/w:pStyle w:val="([^"]+)"/) || [])[1] || '';
		const jc = (paragraphXml.match(/w:jc w:val="([^"]+)"/) || [])[1] || '';
		const text = sanitizeParagraphText(extractParagraphText(paragraphXml));
		return { xml: paragraphXml, style, jc, text };
	});
}

function extractParagraphText(paragraphXml) {
	const parts = [];
	const regex = /<w:t(?:\s[^>]*)?>([\s\S]*?)<\/w:t>/g;
	let match = regex.exec(paragraphXml);
	while (match) {
		parts.push(match[1]);
		match = regex.exec(paragraphXml);
	}
	return sanitizeParagraphText(parts.join(''));
}

function sanitizeParagraphText(text) {
	return decodeXmlText(text)
		.replace(/<[^>]*>/g, ' ')
		.replace(/\s+/g, ' ')
		.trim();
}

function decodeXmlText(text) {
	return String(text || '')
		.replace(/&lt;/g, '<')
		.replace(/&gt;/g, '>')
		.replace(/&amp;/g, '&')
		.replace(/&quot;/g, '"')
		.replace(/&apos;/g, "'");
}

function getHeadingLevel(style) {
	const normalized = String(style || '');
	const headingMatch = normalized.match(/^Heading(\d+)$/);
	if (headingMatch) {
		return Number(headingMatch[1]);
	}
	if (normalized === '1') {
		return 1;
	}
	if (normalized === '20') {
		return 2;
	}
	if (normalized === '3' || normalized === '41') {
		return 3;
	}
	return 0;
}

function isTemplateHeading(paragraph) {
	return getHeadingLevel(paragraph.style) > 0;
}

function normalizeHeadingKey(text) {
	return sanitizeParagraphText(text)
		.toLowerCase()
		.replace(/^\d+([.)]\d+)*[.)]?\s*/, '')
		.trim();
}

function isTocParagraph(paragraph) {
	if (/^TOC\d?$/.test(paragraph.style)) {
		return true;
	}
	if (['10', '11', '21', '30'].includes(paragraph.style)) {
		return true;
	}
	const text = paragraph.text.toLowerCase();
	if (text === 'содержание') {
		return true;
	}
	return text.indexOf('toc \\o') >= 0 || text.indexOf('pageref') >= 0;
}

function isInstructionParagraph(paragraph) {
	if (paragraph.style === 'a2' || paragraph.style === 'a') {
		return true;
	}
	const text = paragraph.text.trim();
	if (text.indexOf('2.6.') >= 0) {
		return true;
	}
	if (text.indexOf('Настоящий шаблон устанавливает') >= 0) {
		return true;
	}
	if (text.indexOf('Раздел не обязателен') >= 0) {
		return true;
	}
	if (text.indexOf('следует переименовать') >= 0) {
		return true;
	}
	if (text.indexOf('следует изменить') >= 0) {
		return true;
	}
	return false;
}

function isBodyFillStyle(paragraph) {
	const style = paragraph.style;
	if (['BodyTextIndent', 'UserStyle_25', 'af6', 'aff5', 'TableHeading'].includes(style)) {
		return true;
	}
	if (!style && isTemplateFillSlot(paragraph)) {
		return true;
	}
	return false;
}

function isTemplateFillSlot(paragraph) {
	const text = paragraph.text.trim();
	const short = text.toLowerCase();
	if (short === 'текст' || short === 'текст.' || short === 'текст:') {
		return true;
	}
	if (/^<[^>]+>$/.test(text)) {
		return true;
	}
	if (text.indexOf('Полное наименование организации') >= 0) {
		return true;
	}
	return false;
}

function buildSectionMapFromParagraphs(paragraphs) {
	const map = {};
	const stack = [];
	let currentKey = '';
	let buffer = [];

	const flush = () => {
		if (!currentKey || buffer.length === 0) {
			return;
		}
		const content = buffer.join('\n').trim();
		if (content) {
			map[currentKey] = content;
		}
		buffer = [];
	};

	for (const paragraph of paragraphs) {
		const level = getHeadingLevel(paragraph.style);
		if (level > 0) {
			flush();
			stack.length = level - 1;
			stack[level - 1] = normalizeHeadingKey(paragraph.text);
			currentKey = stack.join('|');
			if (level === 1 && paragraph.text.trim()) {
				map.__title__ = paragraph.text.trim();
			}
			continue;
		}
		if (currentKey && paragraph.text.trim() && !isInstructionParagraph(paragraph)) {
			buffer.push(paragraph.text.trim());
		}
	}
	flush();
	return map;
}

function mergeLegacySectionsIntoMap(map, legacy) {
	if (legacy.characteristics) {
		map.__legacy_characteristics__ = legacy.characteristics;
	}
	if (legacy.outputInfo) {
		map.__legacy_output__ = legacy.outputInfo;
	}
	if (legacy.inputInfo) {
		map.__legacy_input__ = legacy.inputInfo;
	}
	if (legacy.title) {
		map.__title__ = legacy.title;
	}
}

function mergeSectionMaps(target, source) {
	for (const key of Object.keys(source)) {
		if (key.indexOf('__') === 0) {
			continue;
		}
		if (!target[key] && source[key]) {
			target[key] = source[key];
		}
	}
}

function extractInputSectionsByHeading(paragraphs) {
	const byPath = {};
	const byKey = {};
	let intro = '';
	const stack = [];
	let currentPath = '';
	let buffer = [];

	const flush = () => {
		if (!currentPath || buffer.length === 0) {
			return;
		}
		const content = buffer.join('\n').trim();
		if (!content) {
			return;
		}
		byPath[currentPath] = content;
		const lastKey = normalizeHeadingKey(currentPath.split('|').pop() || '');
		if (lastKey && !byKey[lastKey]) {
			byKey[lastKey] = content;
		}
	};

	for (const paragraph of paragraphs) {
		const level = getHeadingLevel(paragraph.style);
		if (level > 0) {
			flush();
			buffer = [];
			stack.length = level - 1;
			stack[level - 1] = normalizeHeadingKey(paragraph.text);
			currentPath = stack.filter(Boolean).join('|');
			continue;
		}
		const text = paragraph.text.trim();
		if (!text) {
			continue;
		}
		if (!currentPath) {
			intro = intro ? `${intro}\n${text}` : text;
			continue;
		}
		buffer.push(text);
	}
	flush();
	return { byPath, byKey, intro };
}

function pickInputSection(input, candidates) {
	for (const candidate of candidates) {
		const normalized = normalizeHeadingKey(candidate);
		if (input.byKey[normalized]) {
			return input.byKey[normalized];
		}
		for (const path of Object.keys(input.byPath)) {
			const pathNorm = normalizeHeadingKey(path);
			const last = normalizeHeadingKey(path.split('|').pop() || '');
			if (
				pathNorm.indexOf(normalized) >= 0 ||
				normalized.indexOf(last) >= 0 ||
				last.indexOf(normalized) >= 0
			) {
				return input.byPath[path];
			}
		}
	}
	return '';
}

function joinSections(...parts) {
	return parts
		.map((part) => String(part || '').trim())
		.filter(Boolean)
		.join('\n\n');
}

function sanitizeMappedContent(text) {
	const cleaned = String(text || '')
		.replace(/[\uE000-\uF8FF]/g, '')
		.replace(/```[\s\S]*?```/g, ' ')
		.replace(/flowchart\s+\w+[\s\S]*/gi, ' ')
		.replace(/\s+/g, ' ')
		.trim();
	if (!cleaned || cleaned.length < 20) {
		return '';
	}
	return cleaned;
}

function buildMissingSectionPlaceholder(stack) {
	const labels = stack
		.filter(Boolean)
		.map((key) => formatSectionLabel(key));
	const path = labels.length ? labels.join(' → ') : 'раздел без заголовка';
	return `Необходимо добавить текст: ${path}.`;
}

function formatSectionLabel(normalizedKey) {
	const text = String(normalizedKey || '').trim();
	if (!text) {
		return 'раздел';
	}
	return text.charAt(0).toUpperCase() + text.slice(1);
}

function setMapContent(map, key, content) {
	const trimmed = String(content || '').trim();
	if (trimmed) {
		map[key] = trimmed;
	}
}

function buildSemanticGostMap(inputParagraphs, projectName) {
	const input = extractInputSectionsByHeading(inputParagraphs);
	const map = {};
	const major = 'характеристики комплекса задач';
