		joinSections(
			sanitizeMappedContent(pickInputSection(input, ['сценарий для пользователя', 'сценарий использования'])),
			sanitizeMappedContent(pickInputSection(input, ['форма «управление файлами»', 'механизм присоединённых файлов р7']))
		)
