function splitBodyContent(templateXml) {
	const bodyStart = templateXml.indexOf('<w:body>');
	const bodyEnd = templateXml.indexOf('</w:body>');
	if (bodyStart < 0 || bodyEnd < 0) {
		throw new Error('Некорректный шаблон: отсутствует w:body');
	}
	return {
		prefix: templateXml.slice(0, bodyStart + 8),
		suffix: templateXml.slice(bodyEnd),
		content: templateXml.slice(bodyStart + 8, bodyEnd),
	};
}

function parseTopLevelBodyBlocks(content) {
	const blocks = [];
	let pos = 0;
	while (pos < content.length) {
		const relP = content.indexOf('<w:p', pos);
		const relTbl = content.indexOf('<w:tbl', pos);
		const relSect = content.indexOf('<w:sectPr', pos);
		const candidates = [
			relP >= 0 ? { start: relP, tag: 'p' } : null,
			relTbl >= 0 ? { start: relTbl, tag: 'tbl' } : null,
			relSect >= 0 ? { start: relSect, tag: 'sectPr' } : null,
		].filter(Boolean);
		if (candidates.length === 0) {
			break;
		}
		candidates.sort((a, b) => a.start - b.start);
		const { start, tag } = candidates[0];
		const end = findMatchingElementEnd(content, start, tag);
		if (end < 0) {
			break;
		}
		blocks.push({ type: tag, xml: content.slice(start, end) });
		pos = end;
	}
	return blocks;
}

function isElementOpen(xml, index, tag) {
	const open = `<w:${tag}`;
	if (!xml.startsWith(open, index)) {
		return false;
	}
	const next = xml[index + open.length];
	return next === '>' || next === ' ' || next === '/';
}

function findMatchingElementEnd(xml, start, tag) {
	if (!isElementOpen(xml, start, tag)) {
		return -1;
	}
	const open = `<w:${tag}`;
	let scan = start + open.length;
	while (scan < xml.length) {
		const ch = xml[scan];
		if (ch === '>' && xml[scan - 1] === '/') {
			return scan + 1;
		}
		if (ch === '>') {
			break;
		}
		scan += 1;
	}
	const close = `</w:${tag}>`;
	let depth = 1;
	for (let i = scan + 1; i < xml.length; i += 1) {
		if (isElementOpen(xml, i, tag)) {
			const innerEnd = findMatchingElementEnd(xml, i, tag);
			if (innerEnd < 0) {
				return -1;
			}
			i = innerEnd - 1;
			continue;
		}
		if (xml.startsWith(close, i)) {
			depth -= 1;
			if (depth === 0) {
				return i + close.length;
			}
			i += close.length - 1;
		}
	}
	return -1;
}

function parseParagraphBlock(paragraphXml) {
	const style = (paragraphXml.match(/w:pStyle w:val="([^"]+)"/) || [])[1] || '';
	const jc = (paragraphXml.match(/w:jc w:val="([^"]+)"/) || [])[1] || '';
	const text = sanitizeParagraphText(extractParagraphText(paragraphXml));
	return { xml: paragraphXml, style, jc, text };
}

function isMainContentHeading(paragraph) {
	const level = getHeadingLevel(paragraph.style);
	if (level !== 1) {
		return false;
	}
	const text = normalizeHeadingKey(paragraph.text);
	return text.indexOf('характеристики комплекса') >= 0;
}

function ensurePageBreakBefore(paragraphXml) {
	if (paragraphXml.indexOf('w:pageBreakBefore') >= 0 || paragraphXml.indexOf('w:type="page"') >= 0) {
		return paragraphXml;
	}
	const pPrMatch = paragraphXml.match(/<w:pPr[\s\S]*?<\/w:pPr>/);
	if (pPrMatch) {
		return paragraphXml.replace(
			pPrMatch[0],
			pPrMatch[0].replace('</w:pPr>', '<w:pageBreakBefore/></w:pPr>')
		);
	}
	return paragraphXml.replace('<w:p>', '<w:p><w:pPr><w:pageBreakBefore/></w:pPr>');
}

function findContentForSection(inputMap, stack) {
	const key = stack.join('|');
	if (inputMap[key]) {
		return inputMap[key];
	}
	const last = normalizeHeadingKey(stack[stack.length - 1] || '');
	if (!last) {
		return '';
	}
	for (const entryKey of Object.keys(inputMap)) {
		if (entryKey.indexOf('__') === 0) {
			continue;
		}
		if (entryKey === last || entryKey.endsWith(`|${last}`)) {
			return inputMap[entryKey];
		}
	}
	return '';
}

function mergeTemplateDocument(templateXml, inputMap, meta) {
	const { prefix, suffix, content } = splitBodyContent(templateXml);
	const blocks = parseTopLevelBodyBlocks(content);
	const stack = [];
	const out = [];
	const fillStats = { filled: 0, missing: 0 };
	const recommendations = [];
	const recommendationSet = new Set();
	let inMainContent = false;

	for (const block of blocks) {
		if (block.type === 'tbl' || block.type === 'sectPr') {
			if (block.type === 'tbl') {
				out.push(fillTitlePlaceholders(block.xml, meta));
			} else {
				out.push(block.xml);
			}
			continue;
		}

		const paragraph = parseParagraphBlock(block.xml);
		let paragraphXml = paragraph.xml;

		if (!inMainContent) {
			if (isMainContentHeading(paragraph)) {
				inMainContent = true;
				paragraphXml = ensurePageBreakBefore(fillTitlePlaceholders(paragraphXml, meta));
				stack.length = 0;
				stack[0] = normalizeHeadingKey(paragraph.text);
				out.push(paragraphXml);
				continue;
			}
			if (isTocParagraph(paragraph)) {
				out.push(fillTitlePlaceholders(paragraphXml, meta));
				continue;
			}
			if (isInstructionParagraph(paragraph)) {
				continue;
			}
			out.push(fillTitlePlaceholders(paragraphXml, meta));
			continue;
		}

		if (isTocParagraph(paragraph) || isInstructionParagraph(paragraph)) {
			continue;
		}

		const level = getHeadingLevel(paragraph.style);
		if (level > 0) {
			stack.length = level - 1;
			stack[level - 1] = normalizeHeadingKey(paragraph.text);
			if (level === 1) {
				paragraphXml = ensurePageBreakBefore(paragraphXml);
			}
			out.push(paragraphXml);
			continue;
		}

		if (isTemplateFillSlot(paragraph) && isBodyFillStyle(paragraph)) {
			let slotContent = findContentForSection(inputMap, stack);
			if (!slotContent) {
				slotContent = buildMissingSectionPlaceholder(stack);
				fillStats.missing += 1;
				const label = stack.filter(Boolean).join(' > ') || 'Раздел без заголовка';
				const recommendation = `Добавить содержимое в раздел: ${label}`;
				if (!recommendationSet.has(recommendation)) {
					recommendationSet.add(recommendation);
					recommendations.push(recommendation);
				}
			} else {
				fillStats.filled += 1;
			}
			out.push(replaceParagraphText(paragraphXml, slotContent));
			continue;
		}

		out.push(paragraphXml);
	}

	const xml = prefix + out.join('') + suffix;
	return { xml, fillStats, recommendations };
}

function fillTitlePlaceholders(xml, meta) {
	const year = String(new Date().getFullYear());
	const organization = escapeXml(meta.organization || 'Заполнить.');
	const systemName = escapeXml(meta.systemName || 'Заполнить.');
	const cipher = escapeXml(meta.cipher || 'Заполнить.');

	let result = String(xml || '')
		.replace(/20ХХ/g, year)
		.replace(/<ГОД>/g, year)
		.replace(/ХХХ\.П4/g, cipher)
		.replace(/>НАИМЕНОВАНИЕ ОРГАНИЗАЦИИ ЗАКАЗЧИКА</g, `>${organization}<`)
		.replace(/>НАИМЕНОВАНИЕ СИСТЕМЫ \/ ПОДСИСТЕМЫ</g, `>${systemName}<`)
		.replace(/&lt;НАИМЕНОВАНИЕ СИСТЕМЫ \/ ПОДСИСТЕМЫ&gt;/gi, systemName)
		.replace(/&lt;НАИМЕНОВАНИЕ ОРГАНИЗАЦИИ ЗАКАЗЧИКА&gt;/gi, organization)
		.replace(/&lt;Наименование системы\/подсистемы&gt;/gi, systemName)
		.replace(/&lt;Шифр темы&gt;/gi, cipher)
		.replace(/&lt;НаименованиеОрганизацииШапка&gt;/gi, organization)
		.replace(/&lt;Наименование АС&gt;/gi, systemName);

	result = result.replace(
		/<w:t>&lt;<\/w:t><\/w:r><w:r(?:\s[^>]*)?><w:t>ГОД<\/w:t><\/w:r><w:r(?:\s[^>]*)?><w:t>&gt;<\/w:t>/gi,
		`<w:t>${year}</w:t>`
	);

	return result;
}

function inferTitleMetaFromInput(paragraphs, projectName) {
	const result = { systemName: '', organization: '', cipher: '' };
	if (projectName) {
		result.systemName = projectName;
	}

	const texts = (paragraphs || [])
		.map((paragraph) => String(paragraph?.text || '').trim())
		.filter(Boolean);

	for (const text of texts.slice(0, 40)) {
		const cipherMatch = text.match(/\b([A-ZА-ЯЁ0-9][\wА-Яа-яЁё.-]{1,30}\.П\d+)\b/);
		if (cipherMatch && !result.cipher) {
			result.cipher = cipherMatch[1];
		}

		const orgMatch = text.match(
			/(?:организаци[яи]\s+заказчик[ае]?|заказчик)\s*[:—-]\s*(.+)$/i
		);
		if (orgMatch && !result.organization) {
			result.organization = orgMatch[1].trim();
		}

		const systemMatch = text.match(
			/(?:наименование\s+(?:системы|подсистемы|ас)|система\/подсистема)\s*[:—-]\s*(.+)$/i
		);
		if (systemMatch && !result.systemName) {
			result.systemName = systemMatch[1].trim();
		}
	}

	if (!result.systemName) {
		const titleCandidate = texts.find(
			(text) =>
				text.length >= 8 &&
				text.length <= 180 &&
				!/^(описание|инструкция|содержание|утвержден|лист|гост|форма)\b/i.test(text)
		);
		if (titleCandidate) {
			result.systemName = titleCandidate;
		}
	}

	return result;
}

function replaceParagraphText(paragraphXml, newText) {
	const pPrMatch = paragraphXml.match(/<w:pPr[\s\S]*?<\/w:pPr>/);
	const pPr = pPrMatch ? pPrMatch[0] : '';
	const rPrMatch = paragraphXml.match(/<w:rPr[\s\S]*?<\/w:rPr>/);
	const rPr = rPrMatch ? rPrMatch[0] : '';
	const lines = String(newText || 'Заполнить.').split('\n');
	let runs = '';
	for (let i = 0; i < lines.length; i += 1) {
		runs += `<w:r>${rPr}<w:t xml:space="preserve">${escapeXml(lines[i])}</w:t></w:r>`;
		if (i < lines.length - 1) {
			runs += `<w:r>${rPr}<w:br/></w:r>`;
		}
	}
	return `<w:p>${pPr}${runs}</w:p>`;
}
function escapeXml(text) {
	return String(text)
		.replace(/&/g, '&amp;')
		.replace(/</g, '&lt;')
		.replace(/>/g, '&gt;')
		.replace(/"/g, '&quot;')
		.replace(/'/g, '&apos;');
}
function normalizeTaskDescriptionContent(rawText, projectName) {
	const cleaned = cleanText(rawText);
	const sections = splitTaskDescriptionSections(cleaned);
	return {
		title: projectName || sections.title || 'Заполнить.',
		characteristics: sections.characteristics,
		outputInfo: sections.outputInfo,
		inputInfo: sections.inputInfo,
	};
}

function splitTaskDescriptionSections(text) {
	const lowered = text.toLowerCase();
	const byHeadings = splitSectionsByHeadings(text);
	if (byHeadings.hasUsefulSections) {
		return {
			title: byHeadings.title,
			characteristics: byHeadings.grounds || byHeadings.purpose || '',
			outputInfo: byHeadings.requirements || '',
			inputInfo: byHeadings.attachments || '',
		};
	}

	const lines = text
		.split('\n')
		.map((line) => line.trim())
		.filter(Boolean);

	return {
		title: lines[0] || '',
		characteristics: extractByMarkers(text, lowered, ['характеристик', 'назначение комплекса', 'комплекс задач'], [
			'выходная информация',
			'входная информация',
		]),
		outputInfo: extractByMarkers(text, lowered, ['выходная информация', 'выходн'], ['входная информация', 'входн']),
		inputInfo: extractByMarkers(text, lowered, ['входная информация', 'входн'], []),
	};
}

function normalizeGost34Content(rawText, projectName) {
	return normalizeTaskDescriptionContent(rawText, projectName);
}

function cleanText(text) {
	return String(text || '')
		.replace(/\r\n/g, '\n')
		.replace(/\u0000/g, ' ')
		.replace(/[ \t]+\n/g, '\n')
		.replace(/\n{3,}/g, '\n\n')
		.trim();
}

function splitSections(text) {
	const byHeadings = splitSectionsByHeadings(text);
	if (byHeadings.hasUsefulSections) {
		return byHeadings;
	}

	const lowered = text.toLowerCase();
	const result = {
		title: '',
		project: '',
		grounds: extractByMarkers(text, lowered, ['основан', 'основание'], ['назначение', 'цель']),
		purpose: extractByMarkers(text, lowered, ['назначение', 'цель'], ['требован', 'характерист']),
		requirements: extractByMarkers(text, lowered, ['требован', 'характерист'], ['состав работ', 'этап']),
		works: extractByMarkers(text, lowered, ['состав работ', 'этап'], ['порядок контроля', 'приемк']),
		acceptance: extractByMarkers(text, lowered, ['порядок контроля', 'приемк'], ['приложен', 'перечень']),
		attachments: extractByMarkers(text, lowered, ['приложен', 'перечень'], []),
	};

	const lines = text
		.split('\n')
		.map((line) => line.trim())
		.filter(Boolean);
	if (lines.length > 0) {
		result.title = lines[0];
	}
	if (lines.length > 1) {
		result.project = lines[1];
	}

	return result;
}

function splitSectionsByHeadings(text) {
	const lines = text
		.split('\n')
		.map((line) => line.trim())
		.filter(Boolean);
	const sections = [];
	let current = null;

	for (const line of lines) {
		const sectionKey = detectSectionKey(line);
		if (sectionKey) {
			if (current) {
				sections.push(current);
			}
			current = { key: sectionKey, content: [] };
			continue;
		}
		if (current) {
			current.content.push(line);
		}
	}
	if (current) {
		sections.push(current);
	}

	const mapped = {
		title: lines[0] || '',
		project: lines[1] || '',
		grounds: '',
		purpose: '',
		requirements: '',
		works: '',
		acceptance: '',
		attachments: '',
		hasUsefulSections: false,
	};

	for (const section of sections) {
		const content = section.content.join('\n').trim();
		if (!content) {
			continue;
		}
		mapped.hasUsefulSections = true;
		mapped[section.key] = content;
	}

	return mapped;
}

function detectSectionKey(line) {
	const normalized = line.toLowerCase().replace(/\s+/g, ' ').trim();
	const heading = normalized.replace(/^\d+([.)]\d+)*[.)]?\s*/, '');

	if (
		heading.indexOf('основан') >= 0 ||
		heading.indexOf('основание') >= 0 ||
		heading.indexOf('для разработки') >= 0
	) {
		return 'grounds';
	}
	if (heading.indexOf('назначен') >= 0 || heading.indexOf('цел') >= 0) {
		return 'purpose';
	}
	if (heading.indexOf('требован') >= 0 || heading.indexOf('характерист') >= 0) {
		return 'requirements';
	}
	if (heading.indexOf('состав') >= 0 || heading.indexOf('этап') >= 0 || heading.indexOf('работ') >= 0) {
		return 'works';
	}
	if (
		heading.indexOf('контрол') >= 0 ||
		heading.indexOf('приемк') >= 0 ||
		heading.indexOf('приёмк') >= 0
	) {
		return 'acceptance';
	}
	if (heading.indexOf('приложен') >= 0 || heading.indexOf('перечень') >= 0) {
		return 'attachments';
	}

	return '';
}

function extractByMarkers(source, sourceLower, startMarkers, endMarkers) {
	let start = -1;
	for (const marker of startMarkers) {
		const idx = sourceLower.indexOf(marker);
		if (idx >= 0 && (start < 0 || idx < start)) {
			start = idx;
		}
	}
	if (start < 0) {
		return '';
	}

	let end = source.length;
	for (const marker of endMarkers) {
		const idx = sourceLower.indexOf(marker, start + 1);
		if (idx >= 0 && idx < end) {
			end = idx;
		}
	}

	return source.slice(start, end).trim();
}

async function handler(state, params) {
	const warnings = [];
	const userEnv = readUserEnv(state);
	const skillStorage = resolveSkillStorage(state);
	const baseUrl = resolveBaseUrl(state, params, skillStorage);
	const login = pickString(params?.login, userEnv.R7_DISK_LOGIN);
	const password = pickString(params?.password, userEnv.R7_DISK_PASSWORD);
	if (!baseUrl) {
		return fail('Не задан R7_DISK_BASE_URL.', warnings);
	}

	const authResult = await ensureAuthToken(
		baseUrl,
		login,
		password,
		skillStorage,
		params?.auth_token
	);
	if (!authResult.ok) {
		return fail(authResult.error, warnings);
	}
	const authToken = authResult.auth_token;

	const templateDirectoryId = resolvePositiveId(
		params?.template_directory_id ?? userEnv.R7_DISK_GOST34_TEMPLATE_DIRECTORY_ID
	);
	const resultDirectoryId = resolvePositiveId(
		params?.result_directory_id ?? userEnv.R7_DISK_GOST34_RESULT_DIRECTORY_ID
	);
	const inputDirectoryId = resolvePositiveId(params?.input_directory_id);
	const templateName = pickString(
		params?.template_name,
		userEnv.R7_DISK_GOST34_TEMPLATE_NAME || 'gost34_task_description_template.docx'
	);
	const inputName = pickString(params?.input_name, params?.name);
	const outputName = buildOutputName(params?.output_name, inputName);

	if (templateDirectoryId == null) {
		return fail(
			'Не задан template_directory_id (или R7_DISK_GOST34_TEMPLATE_DIRECTORY_ID).',
			warnings
		);
	}
	if (resultDirectoryId == null) {
		return fail(
			'Не задан result_directory_id (или R7_DISK_GOST34_RESULT_DIRECTORY_ID).',
			warnings
		);
	}
	if (inputDirectoryId == null || !inputName) {
		return fail('Нужны input_directory_id и input_name.', warnings);
	}

	if (!getZlib()) {
		return fail('Для DOCX-обработки нужен zlib в runtime.', warnings);
	}

	const templateLookup = await getDocumentIdByName(baseUrl, authToken, templateDirectoryId, templateName);
	if (!templateLookup.ok || templateLookup.documentId == null) {
		return fail(
			`Шаблон «${templateName}» не найден в папке template_directory_id=${templateDirectoryId}.`,
			warnings
		);
	}
	const inputLookup = await getDocumentIdByName(baseUrl, authToken, inputDirectoryId, inputName);
	if (!inputLookup.ok || inputLookup.documentId == null) {
		return fail(
			`Входной файл «${inputName}» не найден в папке input_directory_id=${inputDirectoryId}.`,
			warnings
		);
	}

	const templateDownloaded = await downloadDocumentBytes(baseUrl, authToken, templateLookup.documentId);
	if (!templateDownloaded.ok) {
		return fail(`Не удалось скачать шаблон: ${templateDownloaded.error}`, warnings);
	}
	const inputDownloaded = await downloadDocumentBytes(baseUrl, authToken, inputLookup.documentId);
	if (!inputDownloaded.ok) {
		return fail(`Не удалось скачать входной файл: ${inputDownloaded.error}`, warnings);
	}

	const templateCheck = validateTemplateBytes(templateDownloaded.bytes, templateName);
	if (!templateCheck.ok) {
		return fail(templateCheck.error, warnings);
	}

	const inputBytes = inputDownloaded.bytes;
	const inputText = extractTextByName(inputName, inputBytes);
	if (!inputText.trim()) {
		warnings.push(
			'Не удалось извлечь достаточно текста из входного файла. Часть секций может быть заполнена заглушками.'
		);
	}
	const projectName = pickString(params?.projectName, params?.project_name);
	const inputParagraphs = extractDocumentParagraphs(inputBytes);
	const inputSectionMap = buildSemanticGostMap(inputParagraphs, projectName);
	mergeSectionMaps(inputSectionMap, buildSectionMapFromParagraphs(inputParagraphs));
	mergeLegacySectionsIntoMap(
		inputSectionMap,
		normalizeTaskDescriptionContent(extractDocxPlainText(inputBytes), projectName)
	);
	const inferredTitle = inferTitleMetaFromInput(inputParagraphs, projectName);
	const meta = {
		systemName:
			projectName ||
			inferredTitle.systemName ||
			inputSectionMap.__title__ ||
			'Заполнить.',
		cipher:
			pickString(params?.cipher, '') || inferredTitle.cipher || 'Заполнить.',
		organization:
			pickString(params?.organization, '') || inferredTitle.organization || 'Заполнить.'
	};

	let outputBytes;
	let fillStats = { filled: 0, missing: 0 };
	let recommendations = [];
	try {
		const built = buildDocxFromTemplate(templateDownloaded.bytes, inputSectionMap, meta);
		outputBytes = built.bytes;
		fillStats = built.fillStats;
		recommendations = built.recommendations;
		warnings.push(
			'Применён шаблон «Описание постановки задачи (комплекса задач)» с сохранением оформления и инженерной рамки.'
		);
	} catch (error) {
		return fail(`Не удалось применить шаблон ГОСТ34: ${errorMessage(error)}`, warnings);
	}

	const conflictPolicy = pickString(params?.conflict_policy, 'suffix').toLowerCase();
	const finalOutputName = await resolveOutputNameByPolicy(
		baseUrl,
		authToken,
		resultDirectoryId,
		outputName,
		conflictPolicy
	);
	if (!finalOutputName.ok) {
		return fail(finalOutputName.error, warnings);
	}

	const uploaded = await performMultipartUpload(
		baseUrl,
		authToken,
		resultDirectoryId,
		finalOutputName.name,
		outputBytes,
		'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
	);
	if (!uploaded.ok) {
		return fail(`Не удалось загрузить результат: ${uploaded.error}`, warnings);
	}

	warnings.push(
		'Документ сформирован по шаблону ГОСТ34 из папки templates и загружен в папку results. Скачивайте оригинальный DOCX из Р7-Диска (не упрощённую копию).'
	);
	if (fillStats.missing > 0) {
		warnings.push(
			`Не заполнено секций: ${fillStats.missing}. В документ добавлены пометки «Необходимо добавить текст».`
		);
	}

	return {
		ok: true,
		operation: 'gost34_generate',
		base_url: baseUrl,
		template_directory_id: templateDirectoryId,
		template_name: templateName,
		template_document_id: templateLookup.documentId,
		input_directory_id: inputDirectoryId,
		input_name: inputName,
		input_document_id: inputLookup.documentId,
		result_directory_id: resultDirectoryId,
		output_name: finalOutputName.name,
		output_document_id: uploaded.document_id,
		output_size_bytes: outputBytes.length,
		filledSlots: fillStats.filled,
		missingSlots: fillStats.missing,
		recommendations,
		warnings,
		agent_message:
			`ГОСТ34-документ «${finalOutputName.name}» создан в папке id=${resultDirectoryId}. ` +
			'Если есть рекомендации, внесите недостающий текст по разделам.'
	};
}

function fail(message, warnings) {
	return {
		ok: false,
		operation: 'gost34_generate',
		error: message,
		warnings: warnings.concat([message]),
		recommendations: [],
		filledSlots: 0,
		missingSlots: 0
	};
}

function buildOutputName(rawOutputName, inputName) {
	const custom = pickString(rawOutputName, '');
	if (custom) return ensureDocxExtension(custom);
	const base = stripExtension(inputName || 'document');
	return ensureDocxExtension(`${sanitizeFileName(base)}_gost34_postanovka.docx`);
}

function ensureDocxExtension(name) {
	const trimmed = String(name || '').trim();
	return /\.docx$/i.test(trimmed) ? trimmed : `${trimmed}.docx`;
}

async function resolveOutputNameByPolicy(baseUrl, authToken, directoryId, name, policy) {
	const exists = await getDocumentIdByName(baseUrl, authToken, directoryId, name);
	if (!exists.ok) return { ok: true, name };
	if (exists.documentId == null) return { ok: true, name };
	if (policy === 'overwrite') {
		await deleteDocument(baseUrl, authToken, exists.documentId);
		return { ok: true, name };
	}
	if (policy === 'error') {
		return { ok: false, error: `Файл «${name}» уже существует в папке результатов.` };
	}
	const stamped = stampOutputName(name);
	return { ok: true, name: stamped };
}

function stampOutputName(name) {
	const dot = name.lastIndexOf('.');
	const base = dot > 0 ? name.slice(0, dot) : name;
	const ext = dot > 0 ? name.slice(dot) : '.docx';
	const now = new Date();
	const stamp =
		String(now.getFullYear()) +
		String(now.getMonth() + 1).padStart(2, '0') +
		String(now.getDate()).padStart(2, '0') +
		'_' +
		String(now.getHours()).padStart(2, '0') +
		String(now.getMinutes()).padStart(2, '0') +
		String(now.getSeconds()).padStart(2, '0');
	return `${base}_${stamp}${ext}`;
}

function stripExtension(path) {
	const lastSlash = Math.max(path.lastIndexOf('/'), path.lastIndexOf('\\'));
	const lastDot = path.lastIndexOf('.');
	if (lastDot > lastSlash) {
		return path.slice(0, lastDot);
	}
	return path;
}

function sanitizeFileName(name) {
	return String(name || '')
		.trim()
		.replace(/[<>:"|?*\u0000-\u001f]/g, '_')
		.replace(/\s+/g, ' ')
		.slice(0, 120);
}

function extractTextByName(fileName, bytes) {
	const lower = String(fileName || '').toLowerCase();
	if (lower.endsWith('.docx')) {
		return extractDocxPlainText(bytes);
	}
	if (lower.endsWith('.txt') || lower.endsWith('.md') || lower.endsWith('.csv') || lower.endsWith('.json')) {
		return decodeUtf8(bytes);
	}
	if (looksLikeZip(bytes)) {
		return extractDocxPlainText(bytes);
	}
	return decodeUtf8(bytes);
}


async function getDocumentIdByName(baseUrl, authToken, directoryId, name) {
	const url =
		`${baseUrl}/api/v1/Documents/GetIdByName?` +
		`name=${encodeURIComponent(name)}&` +
		`directoryId=${encodeURIComponent(String(directoryId))}`;
	const http = await apiRequest('GET', url, authToken);
	if (!http.ok) return { ok: false, error: http.error };
	return { ok: true, documentId: extractDocumentId(http.data) };
}

async function deleteDocument(baseUrl, authToken, documentId) {
	const url = `${baseUrl}/api/v1/Documents/Delete`;
	return apiRequest('POST', url, authToken, { Ids: [documentId] });
}

async function downloadDocumentBytes(baseUrl, authToken, documentId) {
	const url =
		`${baseUrl}/api/v1/Documents/Download?` +
		`id=${encodeURIComponent(String(documentId))}`;
	let response;
	try {
		response = await fetch(url, {
			method: 'GET',
			headers: { Authorization: authToken }
		});
	} catch (err) {
		return { ok: false, error: `Сетевая ошибка download: ${errorMessage(err)}` };
	}
	if (!response.ok) {
		const errText = await readUtf8Text(response);
		return { ok: false, error: `Download HTTP ${response.status}: ${truncate(errText, 240)}` };
	}
	const buffer = await response.arrayBuffer();
	return { ok: true, bytes: new Uint8Array(buffer) };
}

async function performMultipartUpload(baseUrl, authToken, directoryId, fileName, fileBytes, mimeOverride) {
	const url = `${baseUrl}/api/v1/Documents/Upload`;
	const boundary = `----R7Disk${Date.now()}`;
	const contentType = mimeOverride || 'application/octet-stream';
	const bodyBytes = buildMultipartUploadBody(boundary, fileName, contentType, fileBytes);
	let response;
	try {
		response = await fetch(url, {
			method: 'POST',
			headers: {
				Authorization: authToken,
				DirectoryId: String(directoryId),
				'Content-Type': `multipart/form-data; boundary=${boundary}`
			},
			body: toFetchBinaryBody(bodyBytes)
		});
	} catch (err) {
		return { ok: false, error: `Сетевая ошибка upload: ${errorMessage(err)}` };
	}
	const rawText = await readUtf8Text(response);
	if (!response.ok) {
		return { ok: false, error: `Upload HTTP ${response.status}: ${truncate(rawText, 320)}` };
	}
	let payload = null;
	if (rawText) {
		try {
			payload = JSON.parse(rawText);
		} catch {
			payload = rawText;
		}
	}
	const data = unwrapApiData(payload);
	return { ok: true, document_id: extractDocumentId(data), data };
}

function buildMultipartUploadBody(boundary, fileName, contentType, fileBytes) {
	const part1 =
		`--${boundary}\r\n` +
		`Content-Disposition: form-data; name="file"; filename="${escapeHeaderFileName(fileName)}"\r\n` +
		`Content-Type: ${contentType}\r\n\r\n`;
	const part2 = `\r\n--${boundary}--\r\n`;
	const head = encodeUtf8(part1);
	const tail = encodeUtf8(part2);
	const out = new Uint8Array(head.length + fileBytes.length + tail.length);
	out.set(head, 0);
	out.set(fileBytes, head.length);
	out.set(tail, head.length + fileBytes.length);
	return out;
}

function escapeHeaderFileName(name) {
	return String(name || 'file.docx').replace(/[\r\n"]/g, '_');
}

function toFetchBinaryBody(bytes) {
	return bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength);
}

async function apiRequest(method, url, authToken, body = null) {
	const init = {
		method,
		headers: {
			'Content-Type': 'application/json; charset=utf-8',
			Accept: 'application/json; charset=utf-8',
			Authorization: authToken
		}
	};
	if (body != null) init.body = JSON.stringify(body);
	let response;
	try {
		response = await fetch(url, init);
	} catch (err) {
		return { ok: false, error: `Сетевая ошибка ${method} ${url}: ${errorMessage(err)}` };
	}
	const rawText = await readUtf8Text(response);
	let payload = null;
	if (rawText) {
		try {
			payload = JSON.parse(rawText);
		} catch {
			payload = rawText;
		}
	}
	if (!response.ok) return { ok: false, error: `HTTP ${response.status}: ${truncate(rawText, 280)}` };
	return { ok: true, data: unwrapApiData(payload) };
}

function unwrapApiData(payload) {
	if (payload && typeof payload === 'object' && 'Response' in payload) {
		const response = payload.Response;
		if (response && typeof response === 'object' && 'Data' in response) return response.Data ?? payload;
	}
	return payload;
}

function extractDocumentId(payload) {
	if (typeof payload === 'number' && Number.isFinite(payload)) return Math.trunc(payload);
	const data = unwrapApiData(payload);
	if (typeof data === 'number' && Number.isFinite(data)) return Math.trunc(data);
	if (data && typeof data === 'object') {
		if (typeof data.Id === 'number') return data.Id;
		if (typeof data.id === 'number') return data.id;
		if (typeof data.DocumentId === 'number') return data.DocumentId;
	}
	return null;
}

function resolvePositiveId(value) {
	if (typeof value === 'number' && Number.isFinite(value) && value > 0) return Math.trunc(value);
	if (typeof value === 'string' && value.trim()) {
		const parsed = Number(value.trim());
		if (Number.isFinite(parsed) && parsed > 0) return Math.trunc(parsed);
	}
	return null;
}

async function ensureAuthToken(baseUrl, login, password, skillStorage, authTokenParam) {
	let authToken = typeof authTokenParam === 'string' ? authTokenParam.trim() : '';
	if (!authToken && skillStorage) {
		const cached = skillStorage.get('r7_disk_auth_token');
		if (typeof cached === 'string' && cached.trim()) authToken = cached.trim();
	}
	if (authToken) return { ok: true, auth_token: authToken };
	return loginInline(baseUrl, login, password, skillStorage);
}

async function loginInline(baseUrl, login, password, skillStorage) {
	if (!login || !password) {
		return { ok: false, error: 'Нет auth_token и не заданы R7_DISK_LOGIN/R7_DISK_PASSWORD для авто-login.' };
	}
	const url = `${baseUrl}/api/v2/auth/Login`;
	const response = await fetch(url, {
		method: 'POST',
		headers: { 'Content-Type': 'application/json; charset=utf-8' },
		body: JSON.stringify({ Login: login, Password: password })
	});
	const rawText = await readUtf8Text(response);
	let payload;
	try {
		payload = rawText ? JSON.parse(rawText) : {};
	} catch {
		return { ok: false, error: `Login: ответ не JSON (HTTP ${response.status}).` };
	}
	if (!response.ok) return { ok: false, error: `Login HTTP ${response.status}: ${truncate(rawText, 240)}` };
	const authToken = payload?.Response?.Data?.Tokens?.AuthToken;
	if (typeof authToken !== 'string' || !authToken) return { ok: false, error: 'Login: AuthToken не найден.' };
	if (skillStorage) {
		skillStorage.set('r7_disk_auth_token', authToken);
		skillStorage.set('r7_disk_base_url', baseUrl);
	}
	return { ok: true, auth_token: authToken };
}

function readUserEnv(state) {
	const env = state.environment;
	if (!env || typeof env !== 'object') return {};
	const user = env.user;
	if (!user || typeof user !== 'object') return {};
	return user;
}

function resolveBaseUrl(state, params, skillStorage) {
	const userEnv = readUserEnv(state);
	const fromParam = typeof params?.base_url === 'string' ? params.base_url.trim() : '';
	if (fromParam) return fromParam.replace(/\/+$/, '');
	if (skillStorage) {
		const cached = skillStorage.get('r7_disk_base_url');
		if (typeof cached === 'string' && cached.trim()) return cached.trim().replace(/\/+$/, '');
	}
	return pickString('', userEnv.R7_DISK_BASE_URL).replace(/\/+$/, '');
}

function pickString(primary, fallback) {
	if (typeof primary === 'string' && primary.trim()) return primary.trim();
	if (typeof fallback === 'string' && fallback.trim()) return fallback.trim();
	return '';
}

function resolveSkillStorage(state) {
	const caps = state.capabilities;
	if (!caps || typeof caps !== 'object') return null;
	const raw = caps.skillStorage ?? caps.storage ?? caps['key-value-storage'];
	if (!raw || typeof raw !== 'object') return null;
	if (typeof raw.get !== 'function' || typeof raw.set !== 'function') return null;
	return raw;
}

function errorMessage(value) {
	return value instanceof Error ? value.message : String(value);
}

function truncate(text, max) {
	const value = String(text || '');
	return value.length <= max ? value : `${value.slice(0, max)}...`;
}

async function readUtf8Text(response) {
	return response.text();
}
